UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – Visitor Visa (TRV)","shortDescription":"IRCC temporary resident visa · Tourism, family, business · Biometrics may apply","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":15,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current IRCC visitor visa fee (CAD $100) and biometrics fee on canada.ca before quoting clients."},"alert":{"title":"Purpose must match documents","body":"Tourism, family visit, and business visitor files need different evidence. Misaligned purpose is a common refusal reason—align invitation, itinerary, and cover letter."},"tags":[{"label":"Active service","variant":"success"},{"label":"Ties evidence critical","variant":"warning"},{"label":"2–8 weeks","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"2–8 weeks processing","variant":"neutral"},{"label":"CAD $100 + biometrics","variant":"neutral"},{"label":"Strong ties required","variant":"warning"},{"label":"Online application","variant":"success"}],"kpis":[{"label":"Processing time","value":"2–8w","sub":"Varies by country of residence","tone":"primary"},{"label":"Government fee","value":"CAD $100","sub":"+ biometrics CAD $85 if required","tone":"warning"},{"label":"Our approval rate","value":"78%","sub":"~65% industry benchmark","tone":"success"},{"label":"Required docs","value":"10","sub":"+ invitation if applicable","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Temporary Resident Visa (TRV) allowing Indian nationals to visit Canada for tourism, family visits, or short business trips. Most applications are submitted online through the IRCC portal."},{"label":"Eligible applicants","value":"Valid passport · Genuine temporary purpose · Strong ties to India · Sufficient funds · Clean immigration history"},{"label":"Single vs multiple entry","value":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"TRV counterfoil in passport; client must respect stay duration and purpose. Overstay affects future Canada applications."}],"eligibility":[{"criterion":"Valid passport (6+ months validity recommended)","met":true,"note":"Check expiry before booking VAC appointment"},{"criterion":"Proof of purpose (tourism / family / business)","met":true,"note":"Itinerary, invitation letter, or business documents as applicable"},{"criterion":"Proof of funds for trip duration","met":true,"note":"Bank statements, ITR, sponsor letter if applicable"},{"criterion":"Strong ties to home country","met":true,"note":"Employment, property, family, business—document clearly"},{"criterion":"Biometrics completed","met":false,"note":"Book within 30 days of BIL if required"},{"criterion":"Medical exam (if required)","met":false,"note":"Based on residence history and stay plans"},{"criterion":"No prior misrepresentation or serious inadmissibility","met":true}],"redFlagsBanner":"If refused, do not reapply immediately with the same weak ties evidence. Address the specific refusal reason before a new submission.","redFlags":[{"title":"Weak home-country ties","description":"Unemployed applicant with no property, family, or business ties; vague return plan.","fix":"Document employment, business, property, family obligations; employer leave letter","severity":"Very common"},{"title":"Insufficient or unseasoned funds","description":"Large recent deposits, funds not matching income, or no sponsor proof.","fix":"4–6 month bank history; sponsor ITR + employment letter; explain large credits","severity":"Very common"},{"title":"Purpose mismatch","description":"Tourism file with business documents only, or family visit without host invitation.","fix":"Align purpose, cover letter, itinerary, and supporting documents","severity":"Common"},{"title":"Previous refusals not addressed","description":"Canada or other country refusals hidden or not explained in cover letter.","fix":"Full disclosure + changed circumstances + stronger evidence","severity":"High"},{"title":"Overstated stay or vague itinerary","description":"Long stay without credible reason or no hotel/flight bookings where appropriate.","fix":"Realistic itinerary; explain accommodation; show return ticket intent","severity":"Common"},{"title":"Biometrics deadline missed","description":"BIL expired before VAC appointment completed.","fix":"Book biometrics within days of BIL; track confirmation","severity":"Medium"}],"faqs":[{"q":"Can we guarantee approval for a strong profile?","a":"No. IRCC officers assess each case individually. We can improve file quality but never promise approval."},{"q":"How much funds should a tourist show?","a":"Enough to cover flights, accommodation, and daily expenses for the planned stay. Verify current IRCC guidance; typically CAD $2,000–5,000+ depending on duration and who pays."},{"q":"Is an invitation letter mandatory for family visits?","a":"Not always legally required, but strongly recommended when visiting relatives. Host should provide invitation, status proof, and address details."},{"q":"Can a refused applicant reapply?","a":"Yes, when circumstances or evidence materially improve. Reapply without addressing refusal reasons usually fails again."},{"q":"Does TRV allow work in Canada?","a":"No. TRV is for temporary visit only. Work requires a work permit unless exempt."},{"q":"How long can a visitor stay?","a":"Officer sets duration at port of entry—often up to 6 months per entry. Client must not overstay."},{"q":"When should biometrics be done?","a":"As soon as possible after Biometric Instruction Letter, typically within 30 days."},{"q":"Can TRV be used to join a spouse studying in Canada?","a":"Sometimes, but assess whether visitor visa or dependant permit is more appropriate. Separate pathways may apply."},{"q":"What is Description for this service?","a":"Temporary Resident Visa (TRV) allowing Indian nationals to visit Canada for tourism, family visits, or short business trips. Most applications are submitted online through the IRCC portal."},{"q":"What is Eligible applicants for this service?","a":"Valid passport · Genuine temporary purpose · Strong ties to India · Sufficient funds · Clean immigration history"},{"q":"What is Single vs multiple entry for this service?","a":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it."},{"q":"Important note on Single vs multiple entry?","a":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"TRV counterfoil in passport; client must respect stay duration and purpose. Overstay affects future Canada applications."},{"q":"Is Valid passport (6+ months validity recommended) required?","a":"Check expiry before booking VAC appointment"},{"q":"Is Proof of purpose (tourism / family / business) required?","a":"Itinerary, invitation letter, or business documents as applicable"},{"q":"Is Proof of funds for trip duration required?","a":"Bank statements, ITR, sponsor letter if applicable"},{"q":"Is Strong ties to home country required?","a":"Employment, property, family, business—document clearly"},{"q":"Is Biometrics completed required?","a":"Book within 30 days of BIL if required"},{"q":"Is Medical exam (if required) required?","a":"Based on residence history and stay plans"},{"q":"Is No prior misrepresentation or serious inadmissibility required?","a":"No prior misrepresentation or serious inadmissibility is typically required."},{"q":"What is the Processing time?","a":"2–8w — Varies by country of residence"},{"q":"What is the Government fee?","a":"CAD $100 — + biometrics CAD $85 if required"},{"q":"What is the Our approval rate?","a":"78% — ~65% industry benchmark"},{"q":"What is the Required docs?","a":"10 — + invitation if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak home-country ties?","a":"Document employment, business, property, family obligations; employer leave letter"},{"q":"Why is Weak home-country ties a problem?","a":"Unemployed applicant with no property, family, or business ties; vague return plan."},{"q":"What if the client has Insufficient or unseasoned funds?","a":"4–6 month bank history; sponsor ITR + employment letter; explain large credits"},{"q":"Why is Insufficient or unseasoned funds a problem?","a":"Large recent deposits, funds not matching income, or no sponsor proof."}],"compliance":["Paid representation in Canada may require RCIC or lawyer—confirm who signs client agreement","Client service agreement and consent must be on file before submission","Never guarantee visa approval; use approved-language only in marketing","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Build ties evidence first—employment letter, property papers, family documents","Match cover letter tone to purpose; avoid generic templates","Book biometrics within days of BIL to avoid preventable delays","For family visits, verify host''s status in Canada before submission","Save final PDF package in client binder for audit"],"postApproval":["Send TRV details and entry conditions to client in writing","Remind client of permitted stay duration and no-work rule","Advise on travel insurance and port-of-entry documents to carry","Register for pre-departure briefing if offered"],"performance":{"ourRate":78,"industryRate":65,"stats":[{"label":"Files this year","value":"96"},{"label":"Approved","value":"75"},{"label":"Refused","value":"15"},{"label":"Withdrawn","value":"6"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":78,"benchmark":65},{"label":"Ties documentation","ours":74,"benchmark":58},{"label":"Financial credibility","ours":76,"benchmark":62},{"label":"Complete checklist first submit","ours":88,"benchmark":68}],"timeline":[{"weeks":"1","title":"Counseling, purpose assessment, fee agreement"},{"weeks":"1–2","title":"Document collection, cover letter, financials"},{"weeks":"2–3","title":"Quality review & IRCC submission"},{"weeks":"3–4","title":"Biometrics (if applicable)"},{"weeks":"2–8","title":"IRCC processing"}],"relatedServices":[{"label":"Canada – Student Visa (Study Permit)","libraryId":""},{"label":"Canada – Super Visa","libraryId":""},{"label":"Canada – Spouse Visa","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial counselor content for Canada TRV with 2026 fee and processing notes."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Indian TRV refusals often cite ties—always collect employer leave letter and property/family evidence even for tourism."},{"author":"Quality","date":"6 Jun 2026","text":"Second review required for all files with prior Canada refusal."}],"resources":[{"title":"IRCC — Visit Canada as a tourist","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada.html","description":"Official visitor visa requirements and how to apply"},{"title":"IRCC — Temporary resident visa","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/apply-visitor-visa.html","description":"Application steps and document checklist"},{"title":"IRCC — Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"When biometrics are required and how to book"},{"title":"IRCC processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current estimates by country and application type"},{"title":"IRCC — Fee list","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-application-fees.html","description":"Current government fees for visitor visa and biometrics"}],"quiz":[{"level":1,"question":"In a temporary resident visa visitor application, which statement about the meaning of a TRV is correct?","options":["A TRV is a visa counterfoil that lets a visa-required foreign national travel to a Canadian port of entry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"It supports travel to Canada but does not itself guarantee admission."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about the visitor visa fee is correct?","options":["The standard temporary resident visa application fee is CAD $100 per person, plus biometrics if required.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The CAD $100 fee is separate from biometrics and other service charges."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about visitor status is correct?","options":["Visitor status allows a temporary stay for tourism, family visits, or other permitted non-work purposes.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A visitor must respect the authorized period and conditions of stay."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about ties to home country is correct?","options":["Employment, family, property, studies, and financial obligations can help show the applicant will leave Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"TRV decisions focus heavily on whether the visit is temporary."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about purpose of visit is correct?","options":["The purpose should be clear, credible, and supported by itinerary, invitation, or event evidence where relevant.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A vague purpose makes it harder for an officer to assess temporary intent."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about financial support is correct?","options":["The applicant must show enough money for travel, living costs, and return transportation.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Funds can come from the applicant or a credible host, but evidence must be clear."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about entry versus visa validity is correct?","options":["A valid TRV permits travel to seek entry; the border officer decides admission and length of stay.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visa validity is not the same as guaranteed status inside Canada."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about biometrics is correct?","options":["Most TRV applicants aged 14 to 79 must give biometrics unless exempt or still valid from a prior application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Biometrics support identity and security screening."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about medical exam is correct?","options":["A medical exam may be required for longer stays, certain countries, or planned work in sensitive settings.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical requirements depend on risk factors and IRCC instructions."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about invitation letters is correct?","options":["An invitation letter can support the purpose of visit but does not guarantee approval.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The visitor still must prove their own eligibility and temporary intent."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about host documents is correct?","options":["Host status, address, relationship, and financial documents may help explain the visit and support arrangements.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Host evidence is useful when the host is paying or providing accommodation."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about family visits is correct?","options":["Visiting family is a valid purpose if the timeline, relationship, and return plan are credible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Family in Canada can support a visit but may also increase overstay concerns if not explained."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about tourism is correct?","options":["Tourism can be a valid purpose when the itinerary, funds, and travel history fit the applicant''s circumstances.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Officers assess whether the trip is realistic and temporary."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about business visitors is correct?","options":["Business visitors may attend meetings or conferences but cannot enter the Canadian labour market without authorization.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Permitted business activities are narrower than working in Canada."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about super visa distinction is correct?","options":["A super visa is different from a regular TRV and is designed for parents and grandparents of citizens or permanent residents.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Super visa eligibility and insurance requirements are distinct from ordinary visitor visas."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about multiple-entry visas is correct?","options":["IRCC often issues multiple-entry TRVs, but each entry is still examined by CBSA.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Multiple-entry validity does not remove the need to comply with visitor conditions."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about passport validity is correct?","options":["The visa cannot normally be valid beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Passport expiry can limit the visa even when the applicant otherwise qualifies."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about previous refusals is correct?","options":["Prior refusals must be disclosed truthfully in the application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Non-disclosure can create a misrepresentation problem worse than the refusal itself."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about criminality is correct?","options":["Criminal convictions or charges can make a visitor inadmissible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"TRV applicants are screened for admissibility as well as purpose and funds."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about work prohibition is correct?","options":["A visitor cannot work in Canada unless specifically authorized under immigration rules.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Visitor status is not a substitute for a work permit."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about study limits is correct?","options":["Visitors can generally study only in short courses of six months or less unless exempt or authorized.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Longer programs usually require a study permit."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about dependants is correct?","options":["Each accompanying family member needs their own application and must satisfy the officer.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Approval of one visitor does not automatically approve every family member."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about travel history is correct?","options":["Lawful travel history can support credibility, but lack of travel history is not an automatic refusal.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Travel history is one factor among funds, ties, and purpose."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about authorized stay is correct?","options":["If no specific date is stamped or documented, many visitors are authorized for up to six months from entry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"CBSA can impose a shorter or different period at examination."},{"level":1,"question":"In a temporary resident visa visitor application, which statement about leaving Canada is correct?","options":["The applicant must convince the officer they will leave Canada at the end of the authorized visit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"This is the core temporary resident requirement for visitor visas."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about IMM 5257?","options":["IMM 5257 is the main application form for a temporary resident visa made outside Canada.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It records identity, travel purpose, background, and admissibility information."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about family information?","options":["IMM 5707 or IMM 5645 may be required depending on the applicant''s country and checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Family information helps IRCC verify identity and relationships."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about document checklist?","options":["The applicant should follow both the IRCC portal checklist and any country-specific instructions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Local visa office requirements can add important documents."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about fee payment?","options":["The applicant pays the CAD $100 TRV fee online, and biometrics fees if required.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Payment is part of completing submission and triggering processing steps."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about biometrics instruction letter?","options":["After submission and biometrics fee payment, IRCC issues a letter used to book biometrics at a VAC or ASC.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should not assume biometrics are complete until enrolled and reflected in the account."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about purpose evidence?","options":["Travel itinerary, invitation letters, event registrations, or hotel bookings should match the stated purpose.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Documents should tell the same story as the application forms."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about employment letters?","options":["A strong employment letter confirms role, salary, approved leave, and expected return date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Employment evidence supports both funds and home-country ties."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about business ownership proof?","options":["Business registration, tax records, invoices, and bank statements can support self-employment ties.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Self-employed applicants need documents that explain ongoing obligations at home."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about bank documents?","options":["Recent statements should show stable balances, income deposits, and enough funds for the trip.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers often scrutinize sudden unexplained deposits."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about host support?","options":["If the host pays expenses, the file should include the host''s invitation, status, income, and accommodation evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Host support does not eliminate the need for the applicant''s own credible plan."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about travel itinerary?","options":["An itinerary should be realistic for the length of stay and the applicant''s budget.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Overly long or expensive plans can raise concerns if funds are limited."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about passport submission?","options":["A passport request is used to place the visa counterfoil for visa-required applicants.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The passport must usually be valid and have space for the counterfoil."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about processing times?","options":["Published TRV times are estimates and vary by country, volume, biometrics, and background checks.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should not book non-refundable travel assuming a specific decision date."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about medical instructions?","options":["If IRCC requests a medical exam, the applicant must use a panel physician and follow the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Medical compliance is part of admissibility processing."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about police or court records?","options":["Police certificates or court records may be needed when criminal history is disclosed or requested.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incomplete criminality evidence can delay or derail a TRV."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about translation?","options":["Non-English or non-French documents generally need certified translations with the original document.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Officers need readable and reliable evidence."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about proof of relationship?","options":["Birth certificates, marriage certificates, photos, and communication records can prove the host relationship.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Relationship evidence helps explain why the visit is happening."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about minor applicants?","options":["Minors may need consent letters, custody documents, and travel authorization from non-accompanying parents.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC and border officers assess child travel safety and consent."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about reapplying after refusal?","options":["A reapplication should respond directly to refusal reasons with better evidence or changed circumstances.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Repeating the same file usually produces the same concerns."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about address history?","options":["Address and travel histories should be complete and consistent with passports and employment records.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Inconsistencies can create credibility issues."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about biometrics validity?","options":["Visitor biometrics are often valid for 10 years and may be reused if still valid.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should check validity before paying or attending again."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about IRCC webform?","options":["A webform can update material changes, but it should not be used as a substitute for a complete initial package.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Important documents belong in the application whenever possible."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about group applications?","options":["Family members can be submitted together, but each person''s forms, fees, and evidence must be complete.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"TRV eligibility is assessed individually."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about decision documents?","options":["Approval leads to passport submission or visa issuance, while refusal letters identify the main concerns.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Applicants should read the decision carefully before taking next steps."},{"level":2,"question":"For a temporary resident visa visitor application, what is the correct process point about arrival examination?","options":["At arrival, the visitor should be ready to explain purpose, funds, host, and return plans consistently.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"CBSA can ask questions even after a TRV is issued."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with an overlong visit request?","options":["A visit that is unusually long for the stated purpose may make the officer doubt the applicant''s real intent.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Trip length should match employment leave, funds, and reason for travel."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with weak employment evidence?","options":["Generic or unverifiable employment letters may fail to prove a strong reason to return home.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers rely on credible, verifiable ties."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with family all travelling together?","options":["If the whole household travels with few remaining ties, the officer may see higher overstay risk.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Applicants should explain remaining obligations and return plans."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with a host paying everything?","options":["Full host sponsorship can help costs but may not overcome weak personal funds or weak home ties.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Visitor decisions assess the applicant''s situation, not only the host''s generosity."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with prior overstays?","options":["Past non-compliance can strongly undermine confidence that the visitor will leave on time.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A persuasive explanation and evidence of resolution are needed."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with undisclosed refusals?","options":["Not declaring prior refusals can trigger misrepresentation concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC can compare immigration histories and application records."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with vague tourism plans?","options":["A generic sightseeing plan without dates, budget, or destinations may look manufactured.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Credible tourism files usually contain realistic details."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with insufficient funds for itinerary?","options":["If the trip costs exceed available funds, the officer may doubt both purpose and ability to leave.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Financial evidence must fit the proposed stay."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with recent job resignation?","options":["Leaving employment shortly before applying can weaken ties and raise migration concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer evaluates circumstances at the time of decision."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with inconsistent host relationship?","options":["Conflicting claims about the host relationship can damage credibility.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Relationship evidence should align with forms, invitation letters, and civil records."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with hidden work plans?","options":["Evidence suggesting the visitor will work without authorization can lead to refusal.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Visitors must not enter the Canadian labour market without proper authorization."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with medical inadmissibility?","options":["A required medical exam can reveal inadmissibility concerns or delay the application.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Visitor eligibility includes health screening where required."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with criminal history?","options":["Even old offences can require careful admissibility analysis before a TRV is approved.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Criminality is separate from whether the visit purpose is genuine."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with large unexplained deposits?","options":["Sudden deposits may be discounted unless the source is documented.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers look for stable, legitimate funds."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with conflicting travel dates?","options":["Different dates across forms, invitation letters, and bookings can make the file appear unreliable.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Consistency helps the officer understand the plan."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with previous long stays in Canada?","options":["Repeated long stays may make the officer question whether the person is living in Canada as a visitor.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Patterns of use matter even when each entry was lawful."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with lack of return ticket?","options":["A missing return ticket is not automatic refusal, but no return plan can contribute to temporary intent concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer needs confidence the stay is temporary."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with minor travelling with one parent?","options":["Missing consent from the other parent can raise child protection and custody concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Consent and custody documents should be clear."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with purpose changing after submission?","options":["A materially changed purpose should be updated with evidence or the original file may become misleading.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers decide based on the record before them."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with invitation from a person without status?","options":["A host with no valid Canadian status may weaken the invitation and raise credibility questions.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Host circumstances are relevant when they support the visit."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with template refusal response?","options":["A reapplication that does not address the specific refusal grounds is unlikely to satisfy the officer.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The new file should add material evidence or explanation."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with dual intent for visitors?","options":["A possible future PR plan is allowed only if the applicant still shows they will leave if required.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Dual intent does not cancel the temporary resident test."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with documents with authenticity concerns?","options":["Questionable bank, job, or civil documents can lead to refusal or a procedural fairness process.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Authenticity issues are treated seriously."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with weak economic establishment?","options":["No employment, assets, studies, or regular income can make it harder to prove return incentives.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Economic establishment is a common TRV risk factor."},{"level":3,"question":"Officer perspective in a temporary resident visa visitor application: what is the key issue with airport questioning?","options":["Inconsistent answers at the port of entry can lead to refusal of entry despite having a visa.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A TRV permits travel for examination; CBSA still decides admission."}],"donts":{"dos":["Document strong ties—employment, property, family obligations","Align purpose, cover letter, and supporting documents","Explain funds source with 4–6 month bank history","Disclose all prior refusals with changed circumstances","Verify current IRCC fees before quoting client"],"donts":["Do not guarantee approval regardless of profile strength","Do not submit without signed client checklist where policy requires","Do not use purpose-inconsistent documents (tourism file with business-only papers)","Do not hide previous refusals from Canada or other countries","Do not miss biometrics deadline after BIL"],"mistakes":["Generic cover letter not explaining return intent","Large unexplained recent bank deposits","Missing employer leave letter for salaried applicants","Overstated trip duration without credible reason","Blurry scans or name mismatches across documents"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Show clients which pages to scan — MRZ visible, no glare, full spread.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample bank statement (mock)","description":"6-month statement with name, account number, and closing balance — explain seasoning.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample invitation / sponsor letter (mock)","description":"Host details, relationship, accommodation, and duration of stay.","mimeType":"application/pdf","docKind":"supporting"},{"title":"Sample travel itinerary (mock)","description":"Flights, hotels, and day-wise plan for visitor visa credibility.","mimeType":"application/pdf","docKind":"supporting"},{"title":"Sample employment / NOC letter (mock)","description":"Employer letter confirming leave, role, salary, and return to India.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample property / ties document (mock)","description":"Sale deed or tax receipt — explain home-country ties.","mimeType":"application/pdf","docKind":"financial"}],"navBucket":"visa"}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000011';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – Spouse / Partner Sponsorship","shortDescription":"IRCC family sponsorship · Inland & outland · PR pathway for spouses","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":25,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current IRCC spousal sponsorship fees (principal + right of permanent residence fee) on canada.ca before quoting."},"alert":{"title":"Genuine relationship evidence","body":"Officers scrutinise relationship genuineness. Weak or inconsistent evidence is a leading refusal factor—build a chronological, document-backed story."},"tags":[{"label":"Active service","variant":"success"},{"label":"Relationship proof critical","variant":"warning"},{"label":"12–18 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"12–18 months processing","variant":"neutral"},{"label":"CAD $1,150+ fees","variant":"neutral"},{"label":"Genuine relationship","variant":"warning"},{"label":"Inland or outland","variant":"success"}],"kpis":[{"label":"Processing time","value":"12–18m","sub":"Varies by stream and office","tone":"primary"},{"label":"Government fee","value":"CAD $1,150+","sub":"+ biometrics, medical","tone":"warning"},{"label":"Our approval rate","value":"91%","sub":"~82% industry benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ relationship evidence","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & third-party","tone":"primary"}],"about":[{"label":"Description","value":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is in Canada."},{"label":"Eligible applicants","value":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"label":"Inland vs outland","value":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Partner receives COPR and completes landing. Maintain relationship genuineness obligations; misrepresentation has serious consequences."}],"eligibility":[{"criterion":"Sponsor is Canadian citizen or PR aged 18+","met":true,"note":"Verify sponsor status and residency obligations"},{"criterion":"Legally valid marriage or qualifying relationship","met":true,"note":"Marriage certificate; common-law needs 12+ months cohabitation proof"},{"criterion":"Genuine relationship evidence","met":true,"note":"Photos, communication, financial mingling, visits"},{"criterion":"Sponsor not in default of prior sponsorship undertakings","met":true},{"criterion":"Medical exam completed","met":false,"note":"Panel physician after instructions"},{"criterion":"Police certificates as required","met":false,"note":"Based on residence history"},{"criterion":"Biometrics completed","met":false,"note":"Both sponsor and applicant if required"}],"redFlagsBanner":"If refused for relationship genuineness, do not reapply with the same weak evidence. Rebuild a chronological, verifiable relationship narrative first.","redFlags":[{"title":"Weak relationship evidence","description":"Few photos, no communication logs, short relationship timeline, or inconsistent stories.","fix":"Chronological timeline; chat/call logs; joint finances; visit stamps; affidavits from family","severity":"Very common"},{"title":"Marriage of convenience suspicion","description":"Large age gap without explanation, met only days before marriage, or prior failed sponsorships.","fix":"Honest narrative; explain how relationship developed; strong third-party support","severity":"High"},{"title":"Incomplete sponsor eligibility","description":"Sponsor on social assistance, prior undertaking default, or not meeting residency for PR sponsors.","fix":"Verify sponsor eligibility checklist on canada.ca before fee collection","severity":"High"},{"title":"Wrong stream (inland vs outland)","description":"Applied inland when partner cannot remain legally in Canada, or outland without travel plan clarity.","fix":"Assess partner''s current status; choose stream with legal counsel if complex","severity":"Common"},{"title":"Missing or inconsistent forms","description":"IMM forms incomplete, dates mismatch across documents, or unsigned declarations.","fix":"Cross-check all dates; dual review before upload","severity":"Common"},{"title":"Undisclosed prior relationships or refusals","description":"Hidden prior marriages, refusals, or misrepresentation history.","fix":"Full disclosure; address changed circumstances in cover letter","severity":"High"}],"faqs":[{"q":"Can we guarantee PR approval for a genuine marriage?","a":"No. Even genuine couples can face requests for additional evidence or refusal if documentation is weak. We improve file quality but never promise approval."},{"q":"Inland or outland—which is faster?","a":"Timelines vary and change. Outland may allow partner to visit during processing; inland may offer open work permit eligibility. Assess case-by-case."},{"q":"How much relationship evidence is enough?","a":"No fixed amount—officers want a credible chronological story: how you met, communication, visits, marriage, shared life plans. Quality over quantity."},{"q":"Can a sponsored spouse work while waiting?","a":"Inland applicants may apply for open work permit after AIP stage in many cases. Verify current IRCC rules at time of counseling."},{"q":"What if marriage is recent?","a":"Recent marriages need stronger evidence—communication history before marriage, visit records, photos, and explanation of relationship development."},{"q":"Does sponsor need minimum income?","a":"Spousal sponsorship generally has no LICO requirement for spouse/partner/child, but sponsor must not be on social assistance (except disability) and must meet undertaking obligations."},{"q":"What happens after refusal?","a":"Review refusal letter carefully. Options may include appeal (IAD) for in-Canada refusals in some cases, or reapplication with stronger evidence."},{"q":"Are common-law partners eligible?","a":"Yes, if they have cohabited continuously for at least 12 months. Evidence of shared residence is essential."},{"q":"What is Description for this service?","a":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is in Canada."},{"q":"What is Eligible applicants for this service?","a":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"q":"What is Inland vs outland for this service?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"Important note on Inland vs outland?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Partner receives COPR and completes landing. Maintain relationship genuineness obligations; misrepresentation has serious consequences."},{"q":"Is Sponsor is Canadian citizen or PR aged 18+ required?","a":"Verify sponsor status and residency obligations"},{"q":"Is Legally valid marriage or qualifying relationship required?","a":"Marriage certificate; common-law needs 12+ months cohabitation proof"},{"q":"Is Genuine relationship evidence required?","a":"Photos, communication, financial mingling, visits"},{"q":"Is Sponsor not in default of prior sponsorship undertakings required?","a":"Sponsor not in default of prior sponsorship undertakings is typically required."},{"q":"Is Medical exam completed required?","a":"Panel physician after instructions"},{"q":"Is Police certificates as required required?","a":"Based on residence history"},{"q":"Is Biometrics completed required?","a":"Both sponsor and applicant if required"},{"q":"What is the Processing time?","a":"12–18m — Varies by stream and office"},{"q":"What is the Government fee?","a":"CAD $1,150+ — + biometrics, medical"},{"q":"What is the Our approval rate?","a":"91% — ~82% industry benchmark"},{"q":"What is the Required docs?","a":"18 — + relationship evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak relationship evidence?","a":"Chronological timeline; chat/call logs; joint finances; visit stamps; affidavits from family"},{"q":"Why is Weak relationship evidence a problem?","a":"Few photos, no communication logs, short relationship timeline, or inconsistent stories."},{"q":"What if the client has Marriage of convenience suspicion?","a":"Honest narrative; explain how relationship developed; strong third-party support"},{"q":"Why is Marriage of convenience suspicion a problem?","a":"Large age gap without explanation, met only days before marriage, or prior failed sponsorships."}],"compliance":["Spousal sponsorship requires licensed RCIC or lawyer for paid representation in Canada—confirm credentials","Client service agreement and consent must be on file before submission","Never guarantee PR approval; marriage alone does not ensure success","Fee quotes must separate consultancy, government, medical, and biometrics"],"proTips":["Build a relationship timeline document before collecting forms","Cross-check every date across marriage cert, photos, and travel history","For recent marriages, include pre-marriage communication evidence","Verify sponsor eligibility before taking full fees","Save relationship evidence binder separately for RFI responses"],"postApproval":["Send COPR and landing instructions to client in writing","Remind client of PR card application after landing","Explain sponsor undertaking period (typically 3 years for spouse)","Register for post-landing settlement briefing if offered"],"performance":{"ourRate":91,"industryRate":82,"stats":[{"label":"Files this year","value":"47"},{"label":"Approved","value":"43"},{"label":"Refused","value":"3"},{"label":"Withdrawn","value":"1"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":91,"benchmark":82},{"label":"Relationship evidence quality","ours":88,"benchmark":72},{"label":"Form accuracy","ours":94,"benchmark":78},{"label":"Complete checklist first submit","ours":90,"benchmark":75}],"timeline":[{"weeks":"1–2","title":"Counseling, sponsor eligibility check, fee agreement"},{"weeks":"2–6","title":"Relationship evidence collection, forms, medical/police"},{"weeks":"6–8","title":"Quality review & IRCC submission"},{"weeks":"8–12","title":"Acknowledgement of receipt (AOR)"},{"weeks":"12–18m","title":"Processing to decision (varies)"}],"relatedServices":[{"label":"Canada – Visitor Visa (TRV)","libraryId":""},{"label":"Canada – Express Entry PR","libraryId":""},{"label":"Canada – Work Permit","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial counselor content for Canada spousal sponsorship with 2026 fee notes."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Arranged marriages need extra care—build pre-marriage communication evidence and family affidavits without appearing fabricated."},{"author":"Quality","date":"6 Jun 2026","text":"Mandatory dual review for all spousal files—date mismatches are the top internal QA finding."}],"resources":[{"title":"IRCC — Sponsor your spouse, partner or child","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigrate-canada/family-sponsorship/spouse-partner-children.html","description":"Official sponsorship requirements and application guide"},{"title":"IRCC — Check processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current spousal sponsorship processing estimates"},{"title":"IRCC — Application fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-application-fees.html","description":"Current sponsorship and right of PR fees"},{"title":"IRCC — Biometrics","url":"https://www.canada.ca/en/immigration-refugees-citizenship/campaigns/biometrics/facts.html","description":"Biometrics requirements for family class"},{"title":"IRCC — Medical exams","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/medical-police/medical-exams.html","description":"When and how to complete immigration medical exam"}],"quiz":[{"question":"What is a leading refusal reason in spousal sponsorship?","options":["Passport colour","Weak or inconsistent relationship evidence","Hotel bookings","Language test scores"],"correctIndex":1,"explanation":"Officers must be satisfied the relationship is genuine.","level":1},{"question":"Common-law partners must generally show:","options":["1 month cohabitation","12+ months continuous cohabitation","No evidence needed","Only wedding photos"],"correctIndex":1,"explanation":"IRCC requires at least 12 months of continuous cohabitation for common-law.","level":1},{"question":"Can counselors guarantee PR for genuine marriages?","options":["Yes, always","No, never guarantee approval","Yes, if married 5+ years","Yes, if sponsor is citizen"],"correctIndex":1,"explanation":"Firm policy: never guarantee immigration outcomes.","level":1},{"question":"Inland sponsorship may allow the partner to:","options":["Skip medical exam","Apply for open work permit in many cases while awaiting decision","Work without any permit immediately","Leave Canada permanently without impact"],"correctIndex":1,"explanation":"Inland stream has specific work permit options—verify current rules.","level":1},{"question":"Before submission, counselors must verify:","options":["Sponsor eligibility and complete relationship timeline","Only marriage certificate","Client''s school marks","Hotel reservations in Canada"],"correctIndex":0,"explanation":"Sponsor eligibility and relationship narrative are foundational.","level":1},{"level":1,"question":"For Canada – Spouse / Partner Sponsorship, which statement about Description is correct?","options":["Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outlan…","Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clea…","Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","Immigration, Refugees and Citizenship Canada (IRCC)"],"correctIndex":0,"explanation":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is i…"},{"level":1,"question":"Canada – Spouse / Partner Sponsorship: what is true regarding Eligible applicants?","options":["Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clea…","Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outlan…","Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","Immigration, Refugees and Citizenship Canada (IRCC)"],"correctIndex":0,"explanation":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"level":1,"question":"A counselor explaining Canada – Spouse / Partner Sponsorship should state correctly about Inland vs outland:","options":["Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision.","Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outlan…","Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clea…","Immigration, Refugees and Citizenship Canada (IRCC)"],"correctIndex":0,"explanation":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision. — verify current rules."},{"level":1,"question":"For Canada – Spouse / Partner Sponsorship, which statement about Key authority is correct?","options":["Immigration, Refugees and Citizenship Canada (IRCC)","Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outlan…","Legally married or qualifying common-law/conjugal relatio