SET academy_metadata = '{"displayName":"Canada – BOWP (Bridging Open Work Permit)","shortDescription":"IRCC BOWP · PR in process · Maintain work status · Open work permit","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Intermediate","learningMinutes":18,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current BOWP program eligibility, AOR requirements, and work permit fee on canada.ca before submission."},"alert":{"title":"AOR and status must be verified","body":"BOWP depends on the PR class, stage of processing, current temporary status, and location in Canada. Do not file from assumptions."},"tags":[{"label":"Active service","variant":"success"},{"label":"PR AOR required","variant":"warning"},{"label":"3–5 months","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"3–5 months processing","variant":"neutral"},{"label":"CAD $255 approx","variant":"neutral"},{"label":"Open work permit","variant":"success"},{"label":"Status-sensitive","variant":"warning"}],"kpis":[{"label":"Processing time","value":"3–5m","sub":"Varies by workload","tone":"primary"},{"label":"Government fee","value":"CAD $255","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"90%","sub":"~82% benchmark","tone":"success"},{"label":"Required docs","value":"10","sub":"+ AOR and PR proof","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Bridging Open Work Permit for eligible in-Canada applicants who have submitted certain permanent residence applications and need to keep working while PR is processed."},{"label":"Eligible applicants","value":"In Canada · Valid status or eligible restoration · Submitted eligible PR application · Received AOR or passed completeness check where required"},{"label":"Eligible PR classes","value":"Commonly Express Entry, Provincial Nominee Program, Agri-Food Pilot, and certain caregiver or Quebec skilled worker pathways. Verify current IRCC program list.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Client may work in Canada under open work permit conditions while PR continues. Review province restrictions for some nominee cases."}],"eligibility":[{"criterion":"Client is physically in Canada when applying","met":true},{"criterion":"Currently holds valid temporary resident status or is eligible to restore status","met":true,"note":"Check expiry date before filing"},{"criterion":"Submitted eligible permanent residence application","met":true},{"criterion":"Has AOR or proof PR application passed completeness check as required","met":true,"note":"Do not use payment receipt alone"},{"criterion":"Current work permit expires within the allowed BOWP window or is already covered by maintained status","met":true},{"criterion":"Passport valid for requested work permit period","met":true},{"criterion":"Provincial nomination has no employment restriction, if PNP-based","met":true,"note":"Employer restriction may block open permit"},{"criterion":"No inadmissibility, misrepresentation, or unresolved removal issue","met":true},{"criterion":"Correct work permit category and fees selected in IRCC portal","met":true}],"redFlagsBanner":"If the PR application is not eligible or AOR is missing, do not submit a BOWP. Assess employer-specific extension, visitor record, or restoration options first.","redFlags":[{"title":"No valid AOR","description":"Client only has PR payment receipt, profile submission confirmation, or nomination letter.","fix":"Wait for AOR/completeness proof or use another temporary status strategy","severity":"High"},{"title":"Wrong PR category","description":"PR stream is not currently listed by IRCC as BOWP-eligible.","fix":"Verify program delivery instructions and choose another work permit option","severity":"High"},{"title":"Applicant outside Canada","description":"BOWP is intended for eligible applicants in Canada.","fix":"Confirm location and assess outside-Canada work permit or wait to return legally","severity":"High"},{"title":"Expired status beyond restoration","description":"Client lost status and restoration deadline has passed.","fix":"Escalate before filing; do not present BOWP as a cure for no status","severity":"Very common"},{"title":"Employer-restricted PNP nomination","description":"Nomination or support letter restricts employment.","fix":"Review nomination conditions; consider employer-specific permit route","severity":"Common"},{"title":"Passport expiring soon","description":"Short passport validity can shorten the work permit.","fix":"Renew passport before applying where timeline allows","severity":"Medium"},{"title":"Incorrect fee or application type","description":"Portal selection misses open work permit holder fee or wrong work permit category.","fix":"Use checklist review before payment and submission","severity":"Common"}],"faqs":[{"q":"Can every PR applicant get a BOWP?","a":"No. Only specific PR classes and processing stages qualify. Verify current IRCC BOWP instructions for the client''s exact pathway."},{"q":"Is an Express Entry profile enough?","a":"No. The client generally needs a submitted PR application and AOR after invitation, not just an active profile."},{"q":"Can the client keep working after applying?","a":"If they applied before their current work permit expired and meet maintained status rules, they may be able to continue under previous conditions. Confirm facts before advising."},{"q":"Can a BOWP be employer-specific?","a":"BOWP is usually open, but some PNP or Quebec-linked cases may have restrictions or separate requirements."},{"q":"What if the current permit expires next week?","a":"Prioritize same-day document review and submission if eligible. Missing the expiry date can force restoration and stop work."},{"q":"Can spouse or dependants apply too?","a":"They may have separate eligibility for open work permit, study permit, or visitor status. Do not bundle without assessing each dependant."},{"q":"Does BOWP guarantee PR approval?","a":"No. It only supports temporary work status while the PR application is processed."},{"q":"How long is the BOWP issued for?","a":"IRCC decides based on program rules, passport validity, and processing context. Counselors should avoid promising a fixed duration."},{"q":"Can the client travel while BOWP is processing?","a":"Travel can affect re-entry and work authorization. Review TRV/eTA, status, and risk before travel."},{"q":"What if PR is refused while BOWP is valid?","a":"Temporary status must be reassessed immediately. The client may need a new status strategy before the work permit expires."},{"q":"What is Description for this service?","a":"Bridging Open Work Permit for eligible in-Canada applicants who have submitted certain permanent residence applications and need to keep working while PR is processed."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Valid status or eligible restoration · Submitted eligible PR application · Received AOR or passed completeness check where required"},{"q":"What is Eligible PR classes for this service?","a":"Commonly Express Entry, Provincial Nominee Program, Agri-Food Pilot, and certain caregiver or Quebec skilled worker pathways. Verify current IRCC program list."},{"q":"Important note on Eligible PR classes?","a":"Commonly Express Entry, Provincial Nominee Program, Agri-Food Pilot, and certain caregiver or Quebec skilled worker pathways. Verify current IRCC program list."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Client may work in Canada under open work permit conditions while PR continues. Review province restrictions for some nominee cases."},{"q":"Is Client is physically in Canada when applying required?","a":"Client is physically in Canada when applying is typically required."},{"q":"Is Currently holds valid temporary resident status or is eligible to restore status required?","a":"Check expiry date before filing"},{"q":"Is Submitted eligible permanent residence application required?","a":"Submitted eligible permanent residence application is typically required."},{"q":"Is Has AOR or proof PR application passed completeness check as required required?","a":"Do not use payment receipt alone"},{"q":"Is Current work permit expires within the allowed BOWP window or is already covered by maintained status required?","a":"Current work permit expires within the allowed BOWP window or is already covered by maintained status is typically required."},{"q":"Is Passport valid for requested work permit period required?","a":"Passport valid for requested work permit period is typically required."},{"q":"Is Provincial nomination has no employment restriction, if PNP-based required?","a":"Employer restriction may block open permit"},{"q":"Is No inadmissibility, misrepresentation, or unresolved removal issue required?","a":"No inadmissibility, misrepresentation, or unresolved removal issue is typically required."},{"q":"Is Correct work permit category and fees selected in IRCC portal required?","a":"Correct work permit category and fees selected in IRCC portal is typically required."},{"q":"What is the Processing time?","a":"3–5m — Varies by workload"},{"q":"What is the Government fee?","a":"CAD $255 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"90% — ~82% benchmark"},{"q":"What is the Required docs?","a":"10 — + AOR and PR proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee work permit or PR approval; use approved-language only","Confirm paid representation authority for Canadian immigration filings","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Check PR class and AOR before collecting BOWP filing documents","Calendar the current permit expiry date and restoration deadline immediately","Upload the AOR and PR application proof in a clearly named file","For PNP cases, review nomination conditions before promising an open permit","Renew passport early if expiry could shorten the permit","Save the submitted forms and payment receipt in the client binder"],"postApproval":["Send approval letter and work permit validity dates to client","Explain open work permit conditions and any printed restrictions","Remind client to maintain PR application updates and respond to IRCC requests","Review SIN renewal and employer record update steps","Schedule PR file monitoring check-in before permit expiry"],"performance":{"ourRate":90,"industryRate":82,"stats":[{"label":"Files this year","value":"68"},{"label":"Approved","value":"61"},{"label":"Refused","value":"5"},{"label":"Withdrawn","value":"2"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":90,"benchmark":82},{"label":"AOR verification","ours":94,"benchmark":80},{"label":"Status deadline control","ours":92,"benchmark":78},{"label":"Correct category selection","ours":91,"benchmark":76}],"timeline":[{"weeks":"1","title":"PR class, AOR, and status verification"},{"weeks":"1–2","title":"Document collection and portal forms"},{"weeks":"2","title":"Quality review and IRCC submission"},{"weeks":"3–5m","title":"IRCC processing and status monitoring"}],"relatedServices":[{"label":"Canada – Express Entry PR","libraryId":""},{"label":"Canada – Work Permit","libraryId":""},{"label":"Canada – Spouse / Dependent Open Work Permit","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial BOWP counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"BOWP screening starts with PR category, AOR, in-Canada location, and current status. Escalate PNP-restricted cases."}],"resources":[{"title":"IRCC — Bridging open work permits","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/application-forms-guides/guide-5553-applying-work-permit-inside-canada-extend-change-conditions.html","description":"In-Canada work permit guide used for extension and change of conditions"},{"title":"IRCC — Work permits in Canada","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/apply.html","description":"Official work permit application entry point"},{"title":"IRCC — Extend or change work permit","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/extend-permit.html","description":"Instructions for work permit extensions from inside Canada"},{"title":"IRCC — Maintain status while processing","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/visit-canada/extend-stay/after-apply.html","description":"Maintained status principles after applying before expiry"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current work permit processing estimates"},{"title":"IRCC — Pay your fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/pay-fees.html","description":"Verify current work permit and open work permit holder fees"}],"quiz":[{"level":1,"question":"In a Bridging Open Work Permit application, which statement about what a BOWP is is correct?","options":["A Bridging Open Work Permit lets certain PR applicants keep working in Canada while their PR application is processed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"It bridges from temporary work status to a pending permanent residence decision."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about open work permit meaning is correct?","options":["An open work permit is not tied to one employer, though restrictions may still appear on the permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"BOWP holders can usually work for most employers subject to conditions."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about eligible PR application is correct?","options":["The applicant must have submitted an eligible permanent residence application and reached the required stage for that class.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A mere intention to apply for PR is not enough."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about inside Canada requirement is correct?","options":["BOWP applicants generally must be in Canada when applying.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The program is designed for workers already in Canada needing continuity."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about current status is correct?","options":["The applicant usually needs valid worker status, maintained status from a timely extension, or eligibility to restore worker status.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Status is a threshold issue before work authorization can be granted."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about expiring work permit is correct?","options":["BOWPs are commonly used when a current work permit is expiring before PR is finalized.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The bridge addresses the gap between temporary permit expiry and PR processing."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about expired work permit is correct?","options":["An expired permit may require restoration analysis; it is not the same as a timely BOWP filed before expiry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Late cases are more complex and do not automatically authorize work."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about PR acknowledgement is correct?","options":["An AOR or equivalent proof of submitted PR application is key evidence for many BOWP categories.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC needs proof the PR file exists and has passed the required intake stage."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about Express Entry is correct?","options":["Express Entry applicants generally need an AOR confirming the electronic application for permanent residence was submitted.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A profile or invitation alone is not a complete PR application."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about PNP nominees is correct?","options":["Provincial nominees may be eligible if their nomination supports a BOWP and has no employer restriction that blocks openness.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Nomination conditions matter."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about Quebec applicants is correct?","options":["Certain Quebec-selected skilled worker applicants can be eligible when they meet IRCC''s BOWP criteria.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Quebec selection documents must support the category claimed."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about caregiver categories is correct?","options":["Some caregiver PR pathway applicants may qualify depending on the stage and program rules.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"BOWP eligibility depends on the specific PR class."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about work permit fees is correct?","options":["A BOWP normally requires the work permit processing fee plus the open work permit holder fee.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The open permit fee is separate from the base work permit fee."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about biometrics is correct?","options":["Biometrics may be required if not already valid or exempt.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Work permit processing includes identity screening."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about medical restrictions is correct?","options":["Without a valid immigration medical, the permit may restrict work in health care, childcare, or similar fields.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical results can affect conditions printed on an open work permit."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about spouse work permits is correct?","options":["A spouse may have separate open work permit options depending on the principal applicant''s status and work.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A BOWP does not automatically grant status to family members."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about children''s status is correct?","options":["Children need their own valid visitor or study status documents as applicable.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Family members must each maintain lawful status."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about maintained worker status is correct?","options":["A timely BOWP application before work permit expiry can allow continued work under previous permit conditions while pending.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Maintained status depends on submitting before expiry."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about employer-specific permit holders is correct?","options":["An employer-specific worker may keep working under the old employer-specific conditions during maintained status.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The open nature begins only once the BOWP is approved."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about LMIA distinction is correct?","options":["A BOWP usually does not require a new LMIA because it is based on PR bridging eligibility.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Its legal basis is different from employer-specific LMIA work permits."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about job offer is correct?","options":["A job offer is not usually the core requirement for BOWP eligibility, though some PR classes or nominations have employment conditions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The PR application stage and status matter more."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about passport validity is correct?","options":["The work permit cannot normally be issued beyond passport expiry.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Passport expiry can shorten the BOWP."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about PR refusal is correct?","options":["If the PR application is refused, the basis for bridging may disappear and future status options must be reassessed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The BOWP depends on an active qualifying PR application."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about province of destination is correct?","options":["Some BOWPs may include province restrictions tied to the PR class or nomination.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Open work permits can still contain location conditions."},{"level":1,"question":"In a Bridging Open Work Permit application, which statement about compliance is correct?","options":["Past unauthorized work or status breaches can affect a BOWP application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Work permit extensions include status and admissibility review."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about IMM 5710?","options":["IMM 5710 is the main form to change conditions, extend stay, or remain in Canada as a worker.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It is commonly used for inside-Canada BOWP applications."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about choosing open work permit?","options":["The application should identify the request as an open work permit and include the proper BOWP support evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incorrect form choices can slow or confuse processing."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about AOR upload?","options":["The AOR or PR submission confirmation should be uploaded to prove the qualifying PR application stage.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC uses this to verify bridging eligibility."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about Express Entry proof?","options":["For Express Entry, the electronic APR AOR is the key document, not just an ITA or profile screenshot.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"An invitation is not the same as a submitted PR application."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about PNP nomination upload?","options":["A provincial nomination certificate and nomination details should be included for nominee-based BOWPs.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Employer restrictions or province conditions can affect eligibility."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about current work permit copy?","options":["The applicant should upload the current or most recent work permit to establish status history.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Status evidence is essential for inside-Canada work permit processing."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about passport pages?","options":["Passport identity and stamped pages help confirm identity, validity, and Canadian entry history.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Passport validity limits permit length."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about fee payment?","options":["The applicant usually pays the work permit processing fee and the open work permit holder fee.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Missing the open permit fee can delay or affect the application."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about biometrics process?","options":["If biometrics are required, IRCC issues instructions after submission and the applicant must comply by the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Biometrics completion is a processing requirement."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about medical exam strategy?","options":["Applicants who want to work in health care, childcare, or similar jobs may need a medical exam to avoid restrictions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Medical clearance affects occupational conditions."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about maintained status timing?","options":["Submitting before the current work permit expires is critical if the applicant wants maintained worker status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Late filing does not preserve work authorization."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about restoration package?","options":["If status expired, the applicant may need restoration fees and explanation in addition to the BOWP request.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Restoration is more than a normal extension."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about employment details?","options":["Even for an open permit, form fields should be completed consistently with current work and requested permit type.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incomplete or contradictory form answers can create processing issues."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about family applications?","options":["Spouse and child applications should include their own forms, fees, and evidence of relationship and status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Family status is not automatically extended by the principal BOWP."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about provincial restrictions?","options":["For some nominees, the BOWP may be restricted to the nominating province.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The permit can be open as to employer but still limited geographically."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about checking PR status?","options":["The PR application should remain active while the BOWP is processed.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A withdrawn, returned, or refused PR file can defeat the bridge."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about returned PR application?","options":["If the PR application is returned as incomplete, the BOWP may be refused because there is no qualifying PR application.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Completeness at the PR stage matters."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about proof of residence in Canada?","options":["Address, current status, and employment evidence can help show the applicant is applying from inside Canada.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"BOWP is an in-Canada facilitation."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about document request response?","options":["IRCC requests for updated AOR, nomination, medical, or status documents must be answered by the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Missed requests can cause refusal."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about bridging from maintained status?","options":["A worker already on maintained status may apply only if they still meet the status and timing rules for the requested permit.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Maintained status facts must be carefully documented."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about work while pending?","options":["If filed before expiry, the applicant normally works under the old permit conditions until a decision, not under new open conditions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The BOWP''s open conditions start after approval."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about approval review?","options":["After approval, the worker should check expiry date, employer field, occupation restrictions, and province conditions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Permit errors can affect lawful work."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about TRV after BOWP?","options":["A visa-required worker may need a separate TRV renewal for travel after receiving the BOWP.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A work permit is not a travel visa."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about NOC or job evidence?","options":["Job evidence may matter for spouse eligibility or some PR contexts, even if the BOWP itself is open.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Related applications can depend on the principal''s work details."},{"level":2,"question":"For a Bridging Open Work Permit application, what is the correct process point about submission proof?","options":["The applicant should keep the submission confirmation as evidence of maintained status if filed before expiry.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Employers may ask for proof the worker can keep working."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with only having an Express Entry profile?","options":["An Express Entry profile or ITA is not enough because the PR application has not yet been submitted and acknowledged.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"BOWP eligibility generally starts after the qualifying PR application stage."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with PR application returned incomplete?","options":["A returned PR application removes the foundation for the BOWP and can lead to refusal.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The bridge requires an active qualifying PR file."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with work permit already expired?","options":["If no timely application was filed, the applicant may lack work authorization and need restoration.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Expired status cases require careful timeline analysis."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with working after expiry without maintained status?","options":["Unauthorized work can harm the BOWP, restoration, and future PR credibility.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer will assess compliance with prior conditions."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with employer-specific maintained status?","options":["A worker awaiting BOWP approval after timely filing must keep following the old employer-specific conditions until approval.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Maintained status continues old conditions, not the requested new ones."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with PNP employment restriction?","options":["A nomination with employer restrictions may prevent a fully open BOWP or require different work permit strategy.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Nomination wording can control what IRCC may issue."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with moving provinces as nominee?","options":["Leaving the nominating province can raise concerns about intent and compliance in both BOWP and PR processing.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Province of destination matters for nominee-based cases."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with medical restriction overlooked?","options":["An open permit with medical restrictions may still bar work in health care or childcare.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Open does not mean unrestricted in every occupation."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with passport expiring soon?","options":["A short passport can cause a short BOWP and repeated status problems.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC generally will not issue beyond passport validity."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with spouse assumes automatic extension?","options":["A spouse''s status is not automatically extended by the principal applicant''s BOWP filing.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Each family member needs their own timely application."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with PR refusal while BOWP pending?","options":["If PR is refused before the BOWP decision, IRCC may refuse the BOWP because the bridge no longer exists.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"BOWP eligibility is tied to an active PR application."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with misrepresentation in PR file?","options":["Concerns in the PR application can spill into the BOWP because the same applicant and facts are under review.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"False information can affect all immigration files."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with wrong PR category selected?","options":["Claiming a BOWP under an ineligible PR stream can lead to refusal even if the person has a pending application.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Only specified PR classes qualify."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with restoration and work?","options":["A person applying for restoration generally cannot keep working while restoration is pending.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Restoration does not equal maintained worker status."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with late biometrics?","options":["Missing biometrics deadlines can sink an otherwise eligible BOWP application.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Procedural steps are mandatory."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with unpaid open work permit fee?","options":["Failure to pay the open work permit holder fee can delay processing or require correction.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Open permit issuance depends on correct fees."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with job loss before applying?","options":["Losing the current job does not automatically bar a BOWP, but status, PR eligibility, and nomination conditions must still be met.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The effect depends on the PR class and current permit."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with closed permit compliance history?","options":["Working for an employer not named on a closed permit can create a serious compliance issue.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Past work conditions are reviewed in extension contexts."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with AOR not yet issued?","options":["Submitting before the required acknowledgement can make the BOWP premature.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer needs proof the PR application reached the required stage."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with Quebec selection mismatch?","options":["Quebec applicants must show the correct Quebec selection and eligible PR pathway documents.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Federal BOWP criteria and Quebec documentation must align."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with caregiver pathway stage?","options":["Some caregiver cases depend on specific pathway stage and eligibility, so generic PR proof may not be enough.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The officer checks the exact class rules."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with criminality after PR filing?","options":["A new charge can create admissibility concerns for both the BOWP and PR application.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Work permits are not insulated from admissibility issues."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with travel while pending?","options":["Leaving Canada while a BOWP is pending can complicate status and re-entry, especially for visa-required nationals.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The application is for work authorization in Canada, not travel permission."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with employer pressure to start open work?","options":["Starting a new job before BOWP approval may be unauthorized if maintained status only preserves old conditions.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The requested open conditions are not active until issuance."},{"level":3,"question":"Officer perspective in a Bridging Open Work Permit application: what is the key issue with officer''s core checklist?","options":["The officer verifies active eligible PR, in-Canada status, correct timing, fees, identity, and compliance history.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A strong BOWP file makes each eligibility element easy to confirm."}],"donts":{"dos":["Verify PR category and AOR before submission","Submit before current status expires where possible","Check PNP nomination restrictions","Use current IRCC fee and category instructions","Explain maintained status in writing with limits"],"donts":["Do not file with PR payment receipt only","Do not promise open work rights if status expired","Do not ignore employer-restricted nomination wording","Do not guarantee PR or BOWP approval","Do not overlook passport expiry"],"mistakes":["Using Express Entry profile number instead of PR AOR","Filing after permit expiry without restoration plan","Selecting wrong work permit category in portal","Missing open work permit holder fee","Not saving proof of submission"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Identity scan with clear MRZ and all stamped pages where relevant.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample current work permit (mock)","description":"Shows permit number, employer conditions, and expiry date.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample PR AOR letter (mock)","description":"Acknowledgement confirming submitted permanent residence application.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample PR application confirmation (mock)","description":"Portal screenshot or PDF confirming application class and submission.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample PNP nomination certificate (mock)","description":"Used to verify restrictions and nomination validity for PNP cases.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample employment letter (mock)","description":"Current employment confirmation for context and work history.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample digital photo (mock)","description":"IRCC-compliant photo for online application upload.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample explanation letter (mock)","description":"Counselor letter explaining PR class, status, and BOWP eligibility.","mimeType":"application/pdf","docKind":"immigration"}],"navBucket":"immigration"}'::jsonb, updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000017';

UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – Study Permit Extension","shortDescription":"IRCC study permit extension · In Canada · Continue studies · Maintain status","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Intermediate","learningMinutes":16,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current study permit extension fee, proof of funds amounts, and maintained status instructions on canada.ca before filing."},"alert":{"title":"Apply before permit expiry","body":"A study permit extension is deadline-driven. Late files may require restoration and can interrupt study and work authorization."},"tags":[{"label":"Active service","variant":"success"},{"label":"In-Canada only","variant":"warning"},{"label":"6–12 weeks","variant":"neutral"},{"label":"Online – IRCC","variant":"neutral"}],"chips":[{"label":"6–12 weeks processing","variant":"neutral"},{"label":"CAD $150 approx","variant":"neutral"},{"label":"Maintain student status","variant":"success"},{"label":"Expiry critical","variant":"warning"}],"kpis":[{"label":"Processing time","value":"6–12w","sub":"Check IRCC weekly","tone":"primary"},{"label":"Government fee","value":"CAD $150","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our approval rate","value":"91%","sub":"~84% benchmark","tone":"success"},{"label":"Required docs","value":"11","sub":"+ enrolment proof","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Extension for students already in Canada who need more time on their study permit to continue or complete an eligible program at a Designated Learning Institution."},{"label":"Eligible applicants","value":"In Canada · Current study permit · Continuing studies or new DLI/program · Proof of funds · Applying before expiry where possible"},{"label":"Maintained status","value":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"label":"After approval","value":"Review new expiry date, study and work conditions, DLI obligations, and passport validity for the next extension or PGWP planning."}],"eligibility":[{"criterion":"Client is physically in Canada","met":true},{"criterion":"Current study permit is valid or client is within restoration period","met":true,"note":"Expiry date drives urgency"},{"criterion":"Continues at a DLI or has valid new LOA from DLI","met":true},{"criterion":"Proof of enrolment or transcript shows active study progress","met":true},{"criterion":"Proof of funds covers tuition, living costs, and return transport","met":true},{"criterion":"Passport valid beyond requested extension period","met":true},{"criterion":"No unauthorized work or study history","met":true},{"criterion":"Medical exam completed if IRCC profile requires it","met":false},{"criterion":"Academic gaps, program changes, or delayed completion explained","met":true}],"redFlagsBanner":"If the permit has already expired, stop and assess restoration before advising the client to keep studying or working.","redFlags":[{"title":"Permit already expired","description":"Client missed extension deadline and may have lost study/work authorization.","fix":"Assess restoration eligibility and stop unauthorized activities until resolved","severity":"High"},{"title":"Weak enrolment proof","description":"No current enrolment letter, transcript, or evidence of continued studies.","fix":"Request current DLI letter showing program, status, and expected completion","severity":"Common"},{"title":"Unexplained program delay","description":"Repeated withdrawals, failed terms, or long gaps without explanation.","fix":"Prepare timeline and supporting DLI notes before submission","severity":"Common"},{"title":"Insufficient funds","description":"Bank balance does not cover tuition and living costs or has unexplained deposits.","fix":"Add sponsor proof, tuition receipt, bank history, and source explanation","severity":"Very common"},{"title":"Passport expires soon","description":"Permit cannot usually be issued beyond passport validity.","fix":"Renew passport before extension where time permits","severity":"Medium"},{"title":"Unauthorized work","description":"Client worked beyond permitted conditions or while not eligible.","fix":"Escalate for admissibility and disclosure strategy before filing","severity":"High"},{"title":"Changed DLI without records","description":"Program or institution changed but client lacks updated LOA or transfer proof.","fix":"Collect updated LOA and explain study pathway clearly","severity":"Common"}],"faqs":[{"q":"When should the extension be filed?","a":"File before the current permit expires. IRCC often recommends applying at least 30 days before expiry, but earlier is better when documents are ready."},{"q":"Can the student keep studying after applying?","a":"If they applied before expiry and continue meeting permit conditions, they may be covered by maintained status while IRCC processes the extension."},{"q":"Can the student work while waiting?","a":"Work rights depend on the prior permit conditions and maintained status rules. Confirm before advising the client to continue work."},{"q":"What if the permit expired?","a":"Assess restoration eligibility immediately. The client may need to stop studying or working until status is restored."},{"q":"Is a new LOA required?","a":"Use a new LOA for a new program or DLI. For continuing students, current enrolment proof and expected completion date are usually important."},{"q":"How much money should be shown?","a":"Use current IRCC financial requirements plus unpaid tuition and living costs. Explain large deposits and sponsor sources."},{"q":"Does changing schools affect the extension?","a":"It can. Collect updated DLI evidence and ensure the client complied with IRCC rules for school changes."},{"q":"Can family members extend too?","a":"Dependants may need separate visitor, study, or work extensions. Screen each status independently."},{"q":"Is biometrics required again?","a":"Often biometrics remain valid for 10 years for temporary residence, but verify the client''s biometrics status and IRCC instructions."},{"q":"Will extension approval help PGWP later?","a":"It can support continuous lawful study, but PGWP eligibility depends on DLI, program, full-time status, and completion rules."},{"q":"What is Description for this service?","a":"Extension for students already in Canada who need more time on their study permit to continue or complete an eligible program at a Designated Learning Institution."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Current study permit · Continuing studies or new DLI/program · Proof of funds · Applying before expiry where possible"},{"q":"What is Maintained status for this service?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"Important note on Maintained status?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Review new expiry date, study and work conditions, DLI obligations, and passport validity for the next extension or PGWP planning."},{"q":"Is Client is physically in Canada required?","a":"Client is physically in Canada is typically required."},{"q":"Is Current study permit is valid or client is within restoration period required?","a":"Expiry date drives urgency"},{"q":"Is Continues at a DLI or has valid new LOA from DLI required?","a":"Continues at a DLI or has valid new LOA from DLI is typically required."},{"q":"Is Proof of enrolment or transcript shows active study progress required?","a":"Proof of enrolment or transcript shows active study progress is typically required."},{"q":"Is Proof of funds covers tuition, living costs, and return transport required?","a":"Proof of funds covers tuition, living costs, and return transport is typically required."},{"q":"Is Passport valid beyond requested extension period required?","a":"Passport valid beyond requested extension period is typically required."},{"q":"Is No unauthorized work or study history required?","a":"No unauthorized work or study history is typically required."},{"q":"Is Medical exam completed if IRCC profile requires it required?","a":"Assess whether Medical exam completed if IRCC profile requires it is satisfied for this case."},{"q":"Is Academic gaps, program changes, or delayed completion explained required?","a":"Academic gaps, program changes, or delayed completion explained is typically required."},{"q":"What is the Processing time?","a":"6–12w — Check IRCC weekly"},{"q":"What is the Government fee?","a":"CAD $150 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"91% — ~84% benchmark"},{"q":"What is the Required docs?","a":"11 — + enrolment proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}],"compliance":["Client service agreement and consent must be on file before submission","Never advise unauthorized work or study while status is uncertain","Never guarantee study permit extension approval","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Start extension review 90 days before permit expiry","Ask for current enrolment letter with expected completion date","Match requested extension length to academic plan and passport validity","Explain every study gap or program change in the cover letter","Check work conditions before giving maintained status advice","Keep proof of submission and fee receipt for school and employer records"],"postApproval":["Send new study permit expiry date and conditions to client","Remind client to update school and employer records if needed","Review off-campus work rules and full-time study obligations","Calendar next expiry date and expected completion date","Discuss PGWP planning if program is near completion"],"performance":{"ourRate":91,"industryRate":84,"stats":[{"label":"Files this year","value":"96"},{"label":"Approved","value":"87"},{"label":"Refused","value":"6"},{"label":"Withdrawn","value":"3"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":91,"benchmark":84},{"label":"Timely filing","ours":95,"benchmark":82},{"label":"Academic continuity","ours":89,"benchmark":77},{"label":"Financial documentation","ours":88,"benchmark":75}],"timeline":[{"weeks":"1","title":"Expiry, enrolment, and status screening"},{"weeks":"1–2","title":"DLI letters, financials, and explanation prep"},{"weeks":"2","title":"Portal submission and fee payment"},{"weeks":"6–12","title":"IRCC processing and maintained status monitoring"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – PGWP","libraryId":""},{"label":"Canada – Visitor Record","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial study permit extension counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Prioritize expiry date, active enrolment, study continuity, and funds. Escalate expired status or unauthorized work."}],"resources":[{"title":"IRCC — Extend your study permit","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/extend-study-permit.html","description":"Official extension instructions"},{"title":"IRCC — Study permit conditions","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/while-you-study.html","description":"Rules while studying in Canada"},{"title":"IRCC — Change schools or programs","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/change-schools.html","description":"Instructions for DLI or program changes"},{"title":"IRCC — Restore status as a student","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/extend-study-permit/restore-status.html","description":"Restoration guidance if status expired"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Current study permit extension estimates"},{"title":"IRCC — Pay your fees","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/pay-fees.html","description":"Current study permit fee page"}],"quiz":[{"level":1,"question":"In a study permit extension from inside Canada, which statement about who needs an extension is correct?","options":["A student needs an extension if their study permit will expire before they finish authorized studies in Canada.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The permit expiry must cover the period of study and any authorized stay."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about where the application is made is correct?","options":["A study permit extension is normally submitted from inside Canada before the current permit expires.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada extension rules differ from an outside-Canada study permit application."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about maintained status is correct?","options":["If a complete extension is submitted before expiry, the student can usually keep studying under the old conditions while waiting.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Maintained status protects temporary resident status during processing."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about extension fee is correct?","options":["The standard study permit extension processing fee is CAD $150.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"This is the same base fee as many study permit applications, separate from other possible costs."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about completion letter is correct?","options":["A completion letter is not required just to extend a study permit before studies are completed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Extension evidence usually focuses on current enrolment, remaining studies, and funds."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about proof of enrolment is correct?","options":["Current enrolment or registration evidence helps show the student is actively pursuing studies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC needs proof the student remains a genuine student."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about transcripts is correct?","options":["Transcripts or academic records can show progress and compliance with study conditions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Academic progress supports the need for more time."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about passport validity is correct?","options":["The new study permit cannot normally be issued beyond the passport expiry date.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A short passport can shorten the extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about DLI status is correct?","options":["The student should remain enrolled at a designated learning institution for post-secondary studies.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"DLI compliance is central to maintaining study permit eligibility."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about financial proof is correct?","options":["The student must show enough money to continue paying tuition and living expenses.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada applicants still need credible financial support."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about applying after expiry is correct?","options":["After expiry, a student may need restoration and cannot rely on maintained status if no timely application was filed.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Restoration is different from a timely extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about restoration period is correct?","options":["Restoration is generally available only within 90 days of losing status and if the person remains eligible.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Restoration is discretionary and does not authorize study while pending unless rules allow."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about TRV distinction is correct?","options":["A study permit extension does not automatically renew a TRV counterfoil for travel.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Status documents and entry visas are different documents."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about co-op conditions is correct?","options":["A student needing mandatory co-op work may require a co-op work permit in addition to the study permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Study authorization does not always cover required work placements."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about part-time study is correct?","options":["Dropping to part-time can affect work authorization and may raise compliance questions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Full-time status often matters for work privileges and future benefits."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about authorized leave is correct?","options":["Approved leave should be documented if it affects enrolment or progress.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC may ask why studies were interrupted."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about program extension is correct?","options":["A school letter showing the new expected completion date supports the need for a longer permit.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"The extension length should match remaining studies."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about conditions on permit is correct?","options":["Students must follow printed and implied conditions, including school and work restrictions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Non-compliance can affect extensions and future applications."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about biometrics is correct?","options":["Biometrics may be required if not already valid or exempt, depending on IRCC instructions.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Inside-Canada biometrics rules can still apply."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about medical exam is correct?","options":["A medical may be needed for certain programs, work settings, or if IRCC requests it.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Medical admissibility can still matter inside Canada."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about family members is correct?","options":["Accompanying family may need their own status extensions tied to the student''s situation.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Each person must maintain valid status in Canada."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about program changes is correct?","options":["Changing programs can be acceptable if the student remains compliant and evidence explains the path.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"IRCC reviews whether the student is genuinely progressing."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about PGWP timing is correct?","options":["Students should not confuse a study permit extension with a post-graduation work permit application.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A PGWP is normally sought after program completion, not as a study extension."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about expiry date awareness is correct?","options":["Students are responsible for tracking the permit expiry date even if the school program continues.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"A valid enrolment letter does not extend status automatically."},{"level":1,"question":"In a study permit extension from inside Canada, which statement about online account notices is correct?","options":["IRCC communicates requests and decisions through the online account or portal used for submission.","It is optional if the applicant writes a detailed cover letter.","It automatically guarantees entry to Canada once the form is submitted.","It is only reviewed after the applicant becomes a permanent resident."],"correctIndex":0,"explanation":"Missing a document request can cause refusal."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about IMM 5709?","options":["IMM 5709 is the main form used to change conditions, extend stay, or remain in Canada as a student.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"It is the standard inside-Canada study permit extension form."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about timely filing?","options":["The application should be submitted before the current study permit expires to preserve maintained status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The submission timestamp matters for status continuity."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about enrolment letter?","options":["A current enrolment letter should show program, DLI, student status, and expected completion date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"This is stronger evidence than an old admission letter alone."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about academic transcript?","options":["A transcript helps document progress, course load, and compliance with study conditions.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC may use it to assess whether the student has actively studied."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about financial uploads?","options":["Recent bank statements, scholarship letters, sponsor proof, or tuition receipts can prove continued funds.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Funds must support the remaining stay, not only the original admission."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about passport upload?","options":["The passport bio page and stamped pages are commonly uploaded to confirm identity and validity.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Passport expiry affects permit length."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about digital photo?","options":["A compliant digital photo may be required as part of the online checklist.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Photo specifications are part of application completeness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about biometrics request?","options":["If biometrics are required, IRCC will issue instructions and a deadline after submission.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Failure to complete biometrics can lead to refusal or delay."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about medical request?","options":["If IRCC requests a medical, the student must use a panel physician and meet the deadline.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Medical requests are formal processing steps."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about client information letter?","options":["A cover letter can explain delays, program changes, reduced course load, or funding details.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Clear explanation helps the officer understand non-standard facts."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about changing conditions?","options":["Students can request changes such as school or work-related conditions when supported by evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The request should match eligibility and documents."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about co-op work permit add-on?","options":["If co-op is mandatory, the student should include school confirmation that work is required for the program.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Mandatory work placements need separate authorization in many cases."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about family extension timing?","options":["Family members should apply to extend their own records before expiry, often together with the student.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Maintained status is personal to each applicant''s timely filing."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about TRV renewal after extension?","options":["After receiving the extended study permit, a visa-required student may apply separately for a new TRV if travel is needed.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"A TRV is for re-entry and is not the same as status in Canada."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about proof of continued DLI enrolment?","options":["The extension package should show the student is still at a DLI and actively registered.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"DLI compliance supports both eligibility and genuineness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about processing while waiting?","options":["During maintained status, the student should avoid leaving Canada unless they understand the effect on re-entry and study authorization.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Travel can complicate maintained status and re-entry."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about refusal while on maintained status?","options":["If the extension is refused, maintained status ends on the refusal date.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"The student must then assess restoration or departure options quickly."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about restoration application?","options":["A restoration request must include restoration fees, the study permit request, and an explanation of lost status.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Restoration is not just a late extension form."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about program deferral evidence?","options":["If studies are delayed, the student should include deferral or revised completion documents from the school.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"IRCC needs evidence explaining why more time is needed."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about authorized leave records?","options":["School-approved leave letters can explain gaps without making the file look abandoned.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Documented leave is better than unexplained inactivity."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about form consistency?","options":["Dates in IMM 5709 should match passport entries, school letters, and previous permit details.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Inconsistencies can create credibility or processing concerns."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about uploading old LOA?","options":["An old LOA alone is usually weaker than current enrolment and expected completion evidence.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Extensions are based on continuing studies, not only initial admission."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about payment receipt?","options":["The IRCC receipt should show the correct study permit extension fee and any other required fees.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Incorrect fees can affect completeness."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about document request deadline?","options":["Additional document requests must be answered by the stated deadline or an extension requested if available.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Missed deadlines can result in refusal."},{"level":2,"question":"For a study permit extension from inside Canada, what is the correct process point about approval document review?","options":["After approval, the student should check name, expiry date, school conditions, and work remarks on the new permit.","It should be uploaded only after IRCC has already made the final decision.","It is replaced by buying a return ticket or submitting a travel itinerary.","It can be ignored if the applicant has previously held Canadian status."],"correctIndex":0,"explanation":"Errors should be addressed promptly."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with applying one day late?","options":["The student may have lost status and cannot claim maintained status from a late extension.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Timely filing is the foundation for maintained status."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with studying after status expired?","options":["Unauthorized study after expiry can create compliance problems for restoration and future applications.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A late applicant must be careful about activities while out of status."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with no academic progress?","options":["Repeated failures, withdrawals, or unexplained gaps may make the officer doubt genuine study compliance.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Extensions require a credible reason for needing more time."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with completion letter confusion?","options":["Asking for an extension after completion may be inappropriate if the person should be pursuing PGWP or visitor status instead.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A completion letter is not required for an in-progress extension, but completion changes the strategy."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with short passport validity?","options":["A short passport can produce a short permit and force another extension soon.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"IRCC generally cannot issue the permit beyond passport expiry."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with leaving Canada on maintained status?","options":["Travel can end the practical benefit of maintained status and create re-entry complications.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Students should understand that maintained status is tied to remaining in Canada."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with working too many hours?","options":["Work-condition violations can undermine the extension and later PGWP eligibility.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Officers consider whether the student complied with permit conditions."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with part-time semesters?","options":["Unexplained part-time study can raise concerns about work authorization and genuine student status.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Documentation of authorized leave or final-term exceptions may be important."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with school losing DLI status?","options":["If the institution is no longer a DLI, the student may need to transfer or explain eligibility carefully.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"DLI status is a threshold issue for study permit holders."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with program hopping?","options":["Frequent unexplained program changes can look like the student is prolonging stay rather than studying.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A coherent academic path reduces officer concern."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with insufficient funds after years in Canada?","options":["Weak current funds can cause refusal even if the original study permit was approved.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Extensions are assessed on present ability to support the stay."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with unpaid tuition balance?","options":["Large unpaid balances may suggest the student cannot continue studies.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Financial records should match school account obligations."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with restoration after 90 days?","options":["Restoration is generally unavailable after the 90-day window, leaving departure and new application options.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The deadline is strict and critical."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with refusal during final semester?","options":["A refusal ends maintained status and may disrupt the ability to lawfully finish the term.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Students should file early enough to manage adverse outcomes."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with misstated completion date?","options":["An inflated or inaccurate completion date can damage credibility and affect permit length.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The school letter should support the requested duration."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with biometrics missed deadline?","options":["Failure to provide biometrics when required can lead to refusal despite strong study evidence.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Procedural compliance matters."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with criminal charge during studies?","options":["New criminality can create admissibility issues during extension processing.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Inside-Canada extensions still screen admissibility."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with medical program without exam?","options":["Programs involving health care, childcare, or similar settings can require medical clearance before work or study conditions are granted.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Medical rules protect public health and vulnerable populations."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with family status not extended?","options":["A student''s approval does not automatically restore or extend a spouse or child''s status.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Each family member needs their own valid status document."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with incorrect form answers?","options":["Wrong answers about previous refusals, status, or background can create credibility or misrepresentation concerns.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"The applicant certifies the accuracy of IMM 5709."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with using a TRV as status proof?","options":["A TRV counterfoil does not authorize remaining in Canada after study permit expiry.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"TRV and study permit status serve different legal functions."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with online account not monitored?","options":["Missing an IRCC request can lead to refusal that might have been avoidable.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Applicants are responsible for account messages."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with unauthorized school transfer?","options":["Failure to follow DLI change rules can appear as non-compliance in an extension review.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"School changes should be handled through IRCC''s required process."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with gap caused by illness?","options":["A medical or personal gap should be documented rather than left unexplained.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"Evidence can turn a red flag into an understandable circumstance."},{"level":3,"question":"Officer perspective in a study permit extension from inside Canada: what is the key issue with officer weighing discretion?","options":["The officer looks for lawful status, genuine continued study, sufficient funds, and compliance with past conditions.","It is harmless because officers approve cases when the applicant is polite.","It can be fixed after refusal by sending documents to the visa office informally.","It matters only at the airport and not during the paper or online review."],"correctIndex":0,"explanation":"A strong extension file answers all four themes clearly."}],"donts":{"dos":["File before the current permit expires whenever possible","Collect current enrolment proof and transcript","Show credible funds for tuition and living costs","Explain program changes and study gaps","Calendar the new expiry date after approval"],"donts":["Do not advise work if status is uncertain","Do not file with expired enrolment evidence","Do not ignore restoration if permit expired","Do not promise approval or exact processing time","Do not overlook passport expiry"],"mistakes":["Applying after expiry without restoration forms","Missing DLI enrolment letter","Unexplained failed terms or withdrawals","Weak bank history with recent deposits","Requesting extension beyond passport validity"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Identity page with passport validity visible.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample current study permit (mock)","description":"Shows permit conditions and expiry date.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample enrolment letter (mock)","description":"DLI confirmation of active enrolment and expected completion.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample transcript (mock)","description":"Academic progress evidence for extension review.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample tuition receipt (mock)","description":"Paid tuition or outstanding fee statement.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample bank statement (mock)","description":"Recent bank history with balance and account holder name.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample sponsor affidavit (mock)","description":"Sponsor commitment with source of income support.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample explanation letter (mock)","description":"Explains delayed completion, program change, or study gap.","mimeType":"application/pdf","docKind":"academic"}],"navBucket":"visa"}'::jsonb, updated_at = now()
