SET academy_metadata = '{"displayName":"UK – Spouse / Partner Visa (Family)","shortDescription":"UKVI family route · Appendix FM · Minimum income & relationship proof","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":25,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current spouse visa fee (£1,846) and IHS rates on gov.uk. Minimum income threshold rules change—verify before quoting."},"alert":{"title":"Financial requirement + genuine relationship","body":"Both minimum income (or savings) and genuine relationship evidence must be met. Weak on either is a refusal risk."},"tags":[{"label":"Active service","variant":"success"},{"label":"Income threshold","variant":"warning"},{"label":"12–24 weeks","variant":"neutral"},{"label":"Online – UKVI","variant":"neutral"}],"chips":[{"label":"12–24 weeks processing","variant":"neutral"},{"label":"£1,846 + IHS","variant":"neutral"},{"label":"Minimum income","variant":"warning"},{"label":"Relationship proof","variant":"warning"}],"kpis":[{"label":"Processing time","value":"12–24w","sub":"Outside UK entry clearance","tone":"primary"},{"label":"Government fee","value":"£1,846","sub":"+ IHS (5 years typical)","tone":"warning"},{"label":"Our approval rate","value":"90%","sub":"~80% industry benchmark","tone":"success"},{"label":"Required docs","value":"19","sub":"+ financial & relationship","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & IHS","tone":"primary"}],"about":[{"label":"Description","value":"Family visa for spouse, civil partner, or unmarried partner of British citizen or person with settled/pre-settled status in UK. Leads to ILR pathway after qualifying period."},{"label":"Eligible applicants","value":"Valid marriage/civil partnership or 2+ years cohabitation · Sponsor meets financial requirement · Adequate accommodation · English A1 (entry) · Genuine relationship"},{"label":"