UPDATE public.service_library
SET academy_metadata = '{"displayName":"USA – Visitor Visa (B1/B2)","shortDescription":"US Embassy B1/B2 · Tourism, family, business · 214(b) interview","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":15,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current B1/B2 MRV fee (USD $185) on travel.state.gov before quoting clients."},"alert":{"title":"214(b) presumption","body":"Every B1/B2 applicant must overcome immigrant intent presumption at interview. Ties to India and temporary purpose are decisive."},"tags":[{"label":"Active service","variant":"success"},{"label":"214(b) critical","variant":"warning"},{"label":"1–4 weeks post-interview","variant":"neutral"},{"label":"Embassy – CGI Federal","variant":"neutral"}],"chips":[{"label":"Interview mandatory","variant":"warning"},{"label":"USD $185 MRV","variant":"neutral"},{"label":"Strong ties required","variant":"warning"},{"label":"DS-160 online","variant":"success"}],"kpis":[{"label":"Processing time","value":"1–4w","sub":"After interview; slot wait extra","tone":"primary"},{"label":"Government fee","value":"USD $185","sub":"MRV non-refundable","tone":"warning"},{"label":"Our approval rate","value":"72%","sub":"~58% industry benchmark","tone":"success"},{"label":"Required docs","value":"8","sub":"+ purpose-specific","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"B1 (business) and B2 (tourism/medical) combined visa for temporary visits to the United States. Indian nationals apply via DS-160 and mandatory consular interview."},{"label":"Eligible applicants","value":"Temporary visit purpose · Strong ties to India · Sufficient funds · Clean immigration history · Honest DS-160"},{"label":"Interview reality","value":"Most decisions made in short interview. Officer assesses intent, ties, and credibility—not document volume alone.","warning":true},{"label":"Key authority","value":"US Department of State — Embassy/Consulate in India"},{"label":"After approval","value":"Visa foil in passport; officer at port of entry decides admission length (often up to 6 months). No work permitted."}],"eligibility":[{"criterion":"Valid passport","met":true,"note":"6+ months validity recommended"},{"criterion":"Clear temporary purpose","met":true,"note":"Tourism, family, business meeting—not employment"},{"criterion":"Strong ties to India","met":true,"note":"Job, business, property, family"},{"criterion":"Proof of funds for trip","met":true,"note":"Bank statements, ITR, sponsor letter"},{"criterion":"DS-160 completed accurately","met":false,"note":"Must match interview answers"},{"criterion":"No prior visa fraud","met":true},{"criterion":"Interview appointment booked","met":false,"note":"Via ustraveldocs.com"}],"redFlagsBanner":"After 214(b) refusal, do not reapply immediately with unchanged profile. Strengthen ties evidence and visit purpose clarity first.","redFlags":[{"title":"Weak ties to India","description":"Unemployed, no assets, young single applicant with vague purpose.","fix":"Employment letter, business registration, property, family dependencies","severity":"Very common"},{"title":"214(b) — immigrant intent signals","description":"Mentions working in USA, long stay without reason, or visiting fiancé without clear plan.","fix":"Clear temporary purpose; return date; no employment intent","severity":"Very common"},{"title":"DS-160 inconsistencies","description":"Travel history, employment, or relatives in US not matching interview.","fix":"Review DS-160 line by line; practice consistent answers","severity":"Common"},{"title":"Prior refusals unchanged","description":"Reapplying without material change in circumstances.","fix":"Wait until ties strengthen; new purpose documentation","severity":"High"},{"title":"Insufficient funds","description":"Cannot explain who pays for trip or recent large deposits.","fix":"Sponsor ITR, bank history, trip budget breakdown","severity":"Common"},{"title":"Over-documented or fake papers","description":"Fabricated invitation or employment letters detected.","fix":"Only genuine documents; honest answers","severity":"High"}],"faqs":[{"q":"Can we guarantee B1/B2 approval?","a":"No. Consular officers decide at interview based on individual assessment."},{"q":"What documents to carry to interview?","a":"Passport, DS-160 confirmation, photo, appointment letter, plus supporting docs—employment, funds, invitation if applicable. Officer may not review all."},{"q":"How to overcome 214(b)?","a":"Demonstrate strong ties, clear temporary purpose, credible funds, and consistent honest answers—not memorised scripts."},{"q":"Can refused applicant reapply?","a":"Yes anytime, but success requires materially changed circumstances or stronger evidence."},{"q":"Does B1/B2 allow work?","a":"No. Employment requires appropriate work visa. B1 allows limited business activities—not US labour market work."},{"q":"How long can visitor stay?","a":"Admission period set at port of entry—often up to 6 months. Must not overstay."},{"q":"Is invitation letter required?","a":"Not mandatory but helpful for family visits. Host''s status proof strengthens file."},{"q":"Ten-year visa means 10-year stay?","a":"No. Visa validity differs from permitted stay per entry. Each entry is subject to CBP admission."},{"q":"What is Description for this service?","a":"B1 (business) and B2 (tourism/medical) combined visa for temporary visits to the United States. Indian nationals apply via DS-160 and mandatory consular interview."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Strong ties to India · Sufficient funds · Clean immigration history · Honest DS-160"},{"q":"What is Interview reality for this service?","a":"Most decisions made in short interview. Officer assesses intent, ties, and credibility—not document volume alone."},{"q":"Important note on Interview reality?","a":"Most decisions made in short interview. Officer assesses intent, ties, and credibility—not document volume alone."},{"q":"What is Key authority for this service?","a":"US Department of State — Embassy/Consulate in India"},{"q":"What is After approval for this service?","a":"Visa foil in passport; officer at port of entry decides admission length (often up to 6 months). No work permitted."},{"q":"Is Valid passport required?","a":"6+ months validity recommended"},{"q":"Is Clear temporary purpose required?","a":"Tourism, family, business meeting—not employment"},{"q":"Is Strong ties to India required?","a":"Job, business, property, family"},{"q":"Is Proof of funds for trip required?","a":"Bank statements, ITR, sponsor letter"},{"q":"Is DS-160 completed accurately required?","a":"Must match interview answers"},{"q":"Is No prior visa fraud required?","a":"No prior visa fraud is typically required."},{"q":"Is Interview appointment booked required?","a":"Via ustraveldocs.com"},{"q":"What is the Processing time?","a":"1–4w — After interview; slot wait extra"},{"q":"What is the Government fee?","a":"USD $185 — MRV non-refundable"},{"q":"What is the Our approval rate?","a":"72% — ~58% industry benchmark"},{"q":"What is the Required docs?","a":"8 — + purpose-specific"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business registration, property, family dependencies"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, young single applicant with vague purpose."},{"q":"What if the client has 214(b) — immigrant intent signals?","a":"Clear temporary purpose; return date; no employment intent"},{"q":"Why is 214(b) — immigrant intent signals a problem?","a":"Mentions working in USA, long stay without reason, or visiting fiancé without clear plan."}],"compliance":["Client service agreement and consent on file before DS-160","Never guarantee visa approval","Do not fabricate documents or coach false statements","Separate consultancy fee from MRV in quotes"],"proTips":["Keep interview answers under 30 seconds—officer controls pace","Bring ties evidence even if officer doesn''t ask","For family visits, know host''s name, status, and address","Avoid mentioning immigrant petitions unless directly asked","Mock interview before appointment for nervous clients"],"postApproval":["Explain visa validity vs admission period to client","Remind no work rule and I-94 compliance","Advise travel insurance and port-of-entry documents","Offer pre-departure tips if available"],"performance":{"ourRate":72,"industryRate":58,"stats":[{"label":"Files this year","value":"134"},{"label":"Approved","value":"96"},{"label":"Refused","value":"32"},{"label":"Withdrawn","value":"6"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":72,"benchmark":58},{"label":"Ties documentation","ours":70,"benchmark":52},{"label":"Interview coaching","ours":75,"benchmark":55},{"label":"DS-160 accuracy","ours":90,"benchmark":72}],"timeline":[{"weeks":"1","title":"Counseling, purpose assessment, fee agreement"},{"weeks":"1–2","title":"DS-160, document prep, slot booking"},{"weeks":"2–3","title":"Mock interview & embassy appointment"},{"weeks":"3–4","title":"Passport return or admin processing"}],"relatedServices":[{"label":"USA – Student Visa (F-1)","libraryId":""},{"label":"USA – Spouse Visa","libraryId":""},{"label":"USA – Green Card","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial B1/B2 counselor content with 214(b) focus."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Client