UPDATE public.service_library
SET academy_metadata = '{"displayName":"USA – Spouse / Fiancé Visa (K-1 / CR-1 / IR-1)","shortDescription":"USCIS family immigration · K-1 fiancé or CR-1/IR-1 spouse · NVC & interview","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":30,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current USCIS I-130/I-129F fees and NVC fees on uscis.gov and travel.state.gov before quoting."},"alert":{"title":"Pathway selection matters","body":"K-1 (fiancé, marry in US) vs CR-1/IR-1 (already married, immigrant visa) have different timelines and steps. Counsel correctly before petition filing."},"tags":[{"label":"Active service","variant":"success"},{"label":"Multi-stage process","variant":"warning"},{"label":"12–24 months","variant":"neutral"},{"label":"USCIS + NVC + Embassy","variant":"neutral"}],"chips":[{"label":"12–24 months total","variant":"neutral"},{"label":"I-130 or I-129F","variant":"neutral"},{"label":"Relationship evidence","variant":"warning"},{"label":"Embassy interview","variant":"success"}],"kpis":[{"label":"Processing time","value":"12–24m","sub":"USCIS + NVC + embassy","tone":"primary"},{"label":"Government fee","value":"USD $1,000+","sub":"Petition + NVC + medical","tone":"warning"},{"label":"Our approval rate","value":"88%","sub":"~78% industry benchmark","tone":"success"},{"label":"Required docs","value":"20","sub":"+ civil documents","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & medical","tone":"primary"}],"about":[{"label":"Description","value":"Family-based immigration for foreign spouse or fiancé of US citizen. CR-1/IR-1 for married couples (immigrant visa); K-1 for fiancés to marry in US within 90 days of entry."},{"label":"Eligible applicants","value":"US citizen petitioner · Valid marriage or bona fide engagement · Genuine relationship · Medical and police clearances · Affidavit of support"},{"label":"K-1 vs CR-1/IR-1","value":"K-1: not yet married, faster initial petition but must marry in US and adjust status. CR-1/IR-1: already married, immigrant visa with conditional PR if marriage under 2 years.","warning":true},{"label":"Key authority","value":"USCIS · National Visa Center (NVC) · US Embassy New Delhi/Mumbai/Chennai/Hyderabad/Kolkata"},{"label":"After approval","value":"Enter US as immigrant (CR-1/IR-1) or K-1 then marry and file I-485. Understand conditional green card rules if applicable."}],"eligibility":[{"criterion":"US citizen petitioner (not green card holder for K-1)","met":true,"note":"LPR sponsors spouse via different family preference—confirm category"},{"criterion":"Legally valid marriage or qualifying engagement","met":true,"note":"Marriage cert or proof of meeting in person within 2 years for K-1"},{"criterion":"Genuine relationship evidence","met":true,"note":"Photos, communication, visits, joint plans"},{"criterion":"I-864 affidavit of support","met":false,"note":"Petitioner income 125% poverty guideline or joint sponsor"},{"criterion":"Civil documents (birth, marriage, police)","met":false,"note":"NVC document collection phase"},{"criterion":"Medical exam by panel physician","met":false,"note":"Before embassy interview"},{"criterion":"DS-260 and embassy interview","met":false,"note":"Final stage before visa issuance"}],"redFlagsBanner":"If denied at embassy for relationship concerns, do not refile without addressing specific concerns and strengthening evidence.","redFlags":[{"title":"Bona fide relationship not credible","description":"Minimal contact history, large age gap unexplained, or marriage soon after online-only relationship.","fix":"Document meeting history, visits, communication logs, joint financial plans","severity":"Very common"},{"title":"Insufficient I-864 income","description":"Petitioner income below 125% poverty line without joint sponsor.","fix":"Joint sponsor with tax returns, or petitioner additional evidence of assets","severity":"Common"},{"title":"Wrong pathway chosen","description":"K-1 filed when already married, or CR-1 when not yet married.","fix":"Reassess marital status and timeline before petition","severity":"High"},{"title":"Incomplete civil documents","description":"Missing divorce decrees, name change proof, or police certificates.","fix":"NVC checklist review; obtain certified translations","severity":"Common"},{"title":"Prior immigration violations","description":"Overstay, misrepresentation, or prior visa refusals not disclosed.","fix":"Full disclosure; consult on waivers if needed","severity":"High"},{"title":"Public charge or medical inadmissibility","description":"Medical exam findings or insufficient support without explanation.","fix":"Complete medical early; secure joint sponsor if income weak","severity":"Medium"}],"faqs":[{"q":"K-1 or CR-1—which is better?","a":"Depends on whether couple is already married and timeline preferences. CR-1/IR-1 grants immigrant visa directly; K-1 requires marriage in US then adjustment. No universal ''better''—assess case."},{"q":"Can we guarantee approval?","a":"No. USCIS, NVC, and embassy each review. Genuine relationships can still face delays or requests for evidence."},{"q":"How long total process?","a":"Often 12–24 months depending on pathway, service center, and embassy backlog. Check current processing times on uscis.gov."},{"q":"Can fiancé work on K-1?","a":"K-1 must marry within 90 days and file for work authorisation through adjustment of status—cannot work immediately on entry."},{"q":"What is conditional green card?","a":"If marriage under 2 years at entry, CR-1 recipient gets 2-year conditional card; must file I-751 to remove conditions."},{"q":"Is joint sponsor allowed?","a":"Yes, when petitioner income insufficient for I-864. Joint sponsor must meet income requirements and submit tax returns."},{"q":"What if petitioner was previously married?","a":"Must provide divorce decrees or death certificates for all prior marriages—both petitioner and beneficiary."},{"q":"Can beneficiary visit on B2 during processing?","a":"Risky—214(b) applies and immigrant intent can cause B2 refusal. Counsel honestly on risks."},{"q":"What is Description for this service?","a":"Family-based immigration for foreign spouse or fiancé of US citizen. CR-1/IR-1 for married couples (immigrant visa); K-1 for fiancés to marry in US within 90 days of entry."},{"q":"What is Eligible applicants for this service?","a":"US citizen petitioner · Valid marriage or bona fide engagement · Genuine relationship · Medical and police clearances · Affidavit of support"},{"q":"What is K-1 vs CR-1/IR-1 for this service?","a":"K-1: not yet married, faster initial petition but must marry in US and adjust status. CR-1/IR-1: already married, immigrant visa with conditional PR if marriage under 2 years."},{"q":"Important note on K-1 vs CR-1/IR-1?","a":"K-1: not yet married, faster initial petition but must marry in US and adjust status. CR-1/IR-1: already married, immigrant visa with conditional PR if marriage under 2 years."},{"q":"What is Key authority for this service?","a":"USCIS · National Visa Center (NVC) · US Embassy New Delhi/Mumbai/Chennai/Hyderabad/Kolkata"},{"q":"What is After approval for this service?","a":"Enter US as immigrant (CR-1/IR-1) or K-1 then marry and file I-485. Understand conditional green card rules if applicable."},{"q":"Is US citizen petitioner (not green card holder for K-1) required?","a":"LPR sponsors spouse via different family preference—confirm category"},{"q":"Is Legally valid marriage or qualifying engagement required?","a":"Marriage cert or proof of meeting in person within 2 years for K-1"},{"q":"Is Genuine relationship evidence required?","a":"Photos, communication, visits, joint plans"},{"q":"Is I-864 affidavit of support required?","a":"Petitioner income 125% poverty guideline or joint sponsor"},{"q":"Is Civil documents (birth, marriage, police) required?","a":"NVC document collection phase"},{"q":"Is Medical exam by panel physician required?","a":"Before embassy interview"},{"q":"Is DS-260 and embassy interview required?","a":"Final stage before visa issuance"},{"q":"What is the Processing time?","a":"12–24m — USCIS + NVC + embassy"},{"q":"What is the Government fee?","a":"USD $1,000+ — Petition + NVC + medical"},{"q":"What is the Our approval rate?","a":"88% — ~78% industry benchmark"},{"q":"What is the Required docs?","a":"20 — + civil documents"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & medical"},{"q":"What if the client has Bona fide relationship not credible?","a":"Document meeting history, visits, communication logs, joint financial plans"},{"q":"Why is Bona fide relationship not credible a problem?","a":"Minimal contact history, large age gap unexplained, or marriage soon after online-only relationship."},{"q":"What if the client has Insufficient I-864 income?","a":"Joint sponsor with tax returns, or petitioner additional evidence of assets"},{"q":"Why is Insufficient I-864 income a problem?","a":"Petitioner income below 125% poverty line without joint sponsor."}],"compliance":["Complex immigration petitions may require licensed US immigration attorney—refer when appropriate","Never guarantee green card or visa approval","Client must sign all petitions truthfully","Separate consultancy, USCIS, NVC, medical, and embassy fees in quotes"],"proTips":["Choose K-1 vs CR-1/IR-1 at intake—changing later is costly","Build relationship evidence binder from day one of engagement","Track USCIS and NVC case numbers in shared client portal","Prepare beneficiary for embassy interview on relationship history","Verify I-864 income early; identify joint sponsor if needed"],"postApproval":["Explain entry rules and 90-day marriage deadline for K-1","Remind CR-1/IR-1 entrants of conditional vs immediate 10-year card","Guide on SSN, I-485 or I-751 timeline as applicable","Connect to settlement resources if offered"],"performance":{"our