UPDATE public.service_library
SET academy_metadata = '{"displayName":"USA – Green Card (Employment & Family)","shortDescription":"USCIS · EB categories · Family preference · Multi-year process","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":35,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current USCIS filing fees (I-140, I-485, etc.) on uscis.gov. Green card timelines vary widely by category and country of birth."},"alert":{"title":"Category and priority date matter","body":"Employment-based (EB) and family-based categories have different wait times. Indian-born applicants often face long backlogs in EB-2/EB-3—set realistic expectations."},"tags":[{"label":"Active service","variant":"success"},{"label":"Long timelines","variant":"warning"},{"label":"2–10+ years","variant":"neutral"},{"label":"USCIS + NVC","variant":"neutral"}],"chips":[{"label":"EB or family based","variant":"neutral"},{"label":"Priority date backlog","variant":"warning"},{"label":"PERM for EB-2/3","variant":"success"},{"label":"No guarantee","variant":"warning"}],"kpis":[{"label":"Processing time","value":"2–10+y","sub":"Category & country dependent","tone":"primary"},{"label":"Government fee","value":"USD $2,000+","sub":"Multiple forms over process","tone":"warning"},{"label":"Our approval rate","value":"85%","sub":"~78% benchmark","tone":"success"},{"label":"Required docs","value":"22","sub":"+ employer docs for EB","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & legal","tone":"primary"}],"about":[{"label":"Description","value":"Lawful permanent residence (green card) via employment sponsorship (EB-1/2/3/5) or family petition (I-130). Multi-step process involving PERM, I-140, priority date, and I-485 or consular processing."},{"label":"Eligible applicants","value":"Qualifying job offer/sponsor (EB) or qualifying family relationship · PERM for most EB-2/3 · Priority date current per Visa Bulletin · Medical and character clearances"},{"label":"India backlog reality","value":"Indian-born EB-2/EB-3 applicants often wait years after I-140 approval for priority date to become current. Monitor Visa Bulletin monthly.","warning":true},{"label":"Key authority","value":"USCIS · Department of Labor (PERM) · Department of State (Visa Bulletin/NVC)"},{"label":"After approval","value":"Receive green card; maintain residence; eligible for citizenship after qualifying period (typically 5 years)."}],"eligibility":[{"criterion":"Qualifying EB category or family relationship","met":true},{"criterion":"Employer sponsorship / PERM (EB-2/3)","met":false,"note":"PERM adds 12–18 months"},{"criterion":"I-140 approved","met":false},{"criterion":"Priority date current (Visa Bulletin)","met":false,"note":"Check monthly bulletin"},{"criterion":"I-485 or consular processing eligible","met":false},{"criterion":"Medical exam completed","met":false},{"criterion":"No serious inadmissibility","met":true}],"redFlagsBanner":"If priority date not current, I-485 cannot be filed—monitor Visa Bulletin and maintain lawful status meanwhile.","redFlags":[{"title":"Priority date not current","description":"Client expects green card but Visa Bulletin shows years of backlog.","fix":"Monitor Visa Bulletin; maintain H-1B/status; set realistic timeline","severity":"Very common"},{"title":"PERM recruitment issues","description":"DOL audits or inadequate recruitment advertising.","fix":"Ensure PERM compliance; experienced immigration attorney for PERM","severity":"Common"},{"title":"Status gap during wait","description":"Fell out of status while waiting for priority date.","fix":"Maintain valid non-immigrant status throughout wait","severity":"High"},{"title":"Job change during PERM/I-140","description":"Changed employer before I-140 approved 180+ days.","fix":"Understand AC21 portability rules; may need new PERM","severity":"Common"},{"title":"Incorrect EB category","description":"Filed EB-3 when EB-2 qualifications exist or vice versa.","fix":"Assess education/experience for optimal category","severity":"Common"},{"title":"Medical inadmissibility","description":"Health grounds not addressed.","fix":"Complete medical early; consult on waivers if needed","severity":"Medium"}],"faqs":[{"q":"Can we guarantee green card?","a":"No. Multi-step process with DOL, USCIS, and visa availability. Never promise approval or timeline."},{"q":"How long for Indians EB-2?","a":"Check current Visa Bulletin—often many years backlog. Dates move monthly."},{"q":"What is PERM?","a":"Labor certification proving no qualified US workers available—required for most EB-2/EB-3."},{"q":"Can spouse work during wait?","a":"Depends on status—H-4 EAD, L-2, or EAD with pending I-485 if eligible."},{"q":"What is priority date?","a":"Date PERM filed or I-140 receipt—determines place in queue per Visa Bulletin."},{"q":"EB-1 vs EB-2?","a":"EB-1 for extraordinary ability/multinational managers—no PERM. EB-2 typically needs PERM unless NIW."},{"q":"What is NIW?","a":"National Interest Waiver—EB-2 without PERM if work benefits US national interest."},{"q":"Family-based options?","a":"I-130 through US citizen/LPR relatives—preference categories have own backlogs."},{"q":"What is Description for this service?","a":"Lawful permanent residence (green card) via employment sponsorship (EB-1/2/3/5) or family petition (I-130). Multi-step process involving PERM, I-140, priority date, and I-485 or consular processing."},{"q":"What is Eligible applicants for this service?","a":"Qualifying job offer/sponsor (EB) or qualifying family relationship · PERM for most EB-2/3 · Priority date current per Visa Bulletin · Medical and character clearances"},{"q":"What is India backlog reality for this service?","a":"Indian-born EB-2/EB-3 applicants often wait years after I-140 approval for priority date to become current. Monitor Visa Bulletin monthly."},{"q":"Important note on India backlog reality?","a":"Indian-born EB-2/EB-3 applicants often wait years after I-140 approval for priority date to become current. Monitor Visa Bulletin monthly."},{"q":"What is Key authority for this service?","a":"USCIS · Department of Labor (PERM) · Department of State (Visa Bulletin/NVC)"},{"q":"What is After approval for this service?","a":"Receive green card; maintain residence; eligible for citizenship after qualifying period (typically 5 years)."},{"q":"Is Qualifying EB category or family relationship required?","a":"Qualifying EB category or family relationship is typically required."},{"q":"Is Employer sponsorship / PERM (EB-2/3) required?","a":"PERM adds 12–18 months"},{"q":"Is I-140 approved required?","a":"Assess whether I-140 approved is satisfied for this case."},{"q":"Is Priority date current (Visa Bulletin) required?","a":"Check monthly bulletin"},{"q":"Is I-485 or consular processing eligible required?","a":"Assess whether I-485 or consular processing eligible is satisfied for this case."},{"q":"Is Medical exam completed required?","a":"Assess whether Medical exam completed is satisfied for this case."},{"q":"Is No serious inadmissibility required?","a":"No serious inadmissibility is typically required."},{"q":"What is the Processing time?","a":"2–10+y — Category & country dependent"},{"q":"What is the Government fee?","a":"USD $2,000+ — Multiple forms over process"},{"q":"What is the Our approval rate?","a":"85% — ~78% benchmark"},{"q":"What is the Required docs?","a":"22 — + employer docs for EB"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & legal"},{"q":"What if the client has Priority date not current?","a":"Monitor Visa Bulletin; maintain H-1B/status; set realistic timeline"},{"q":"Why is Priority date not current a problem?","a":"Client expects green card but Visa Bulletin shows years of backlog."},{"q":"What if the client has PERM recruitment issues?","a":"Ensure PERM compliance; experienced immigration attorney for PERM"},{"q":"Why is PERM recruitment issues a problem?","a":"DOL audits or inadequate recruitment advertising."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee visa or immigration approval; use approved-language only","Fee quotes must separate consultancy, government, and third-party costs","Green card cases typically require licensed US immigration attorney"],"proTips":["Check Visa Bulletin monthly with client","Maintain lawful status during entire wait","PERM with experienced attorney—DOL audits real","Document AC21 eligibility if changing jobs post-I-140","Set realistic timeline expectations at sales stage"],"postApproval":["Send green card and conditions","Explain citizenship eligibility timeline","Guide on SS card and state ID","Remind on residency obligations"],"performance":{"ourRate":85,"industryRate":78,"stats":[{"label":"Files this year","value":"45"},{"label":"Approved","value":"38"},{"label":"Refused","value":"5"},{"label":"Withdrawn","value":"2"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":85,"benchmark":78},{"label":"Category assessment","ours":87,"benchmark":72},{"label":"Status maintenance","ours":82,"benchmark":68},{"label":"Timeline expectation setting","ours":90,"benchmark":70}],"timeline":[{"weeks":"6–18m","title":"PERM process (EB-2/3 if applicable)"},{"weeks":"18–24m","title":"I-140 petition"},{"weeks":"Variable years","title":"Wait for priority date current"},{"weeks":"6–18m","title":"I-485 or consular processing"}],"relatedServices":[{"label":"USA – Spouse Visa","libraryId":""},{"label":"USA – Student Visa (F-1)","libraryId":""},{"label":"USA – Visitor Visa","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","su