UPDATE public.service_library
SET academy_metadata = '{"displayName":"Australia – Partner Visa (Subclass 820/801 or 309/100)","shortDescription":"Home Affairs · Partner visa · Onshore/offshore · Relationship & health","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":28,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current partner visa fees (AUD ,850+ approx for primary applicant) on homeaffairs.gov.au before quoting."},"alert":{"title":"Two-stage partner visa","body":"Subclass 309/100 (offshore) or 820/801 (onshore) are two-stage processes. Choose pathway based on where applicant is at time of application."},"tags":[{"label":"Active service","variant":"success"},{"label":"Relationship proof","variant":"warning"},{"label":"12–24 months stage 1","variant":"neutral"},{"label":"Online – ImmiAccount","variant":"neutral"}],"chips":[{"label":"12–24m stage 1","variant":"neutral"},{"label":"AUD ,850+ approx","variant":"neutral"},{"label":"Genuine relationship","variant":"warning"},{"label":"Two-stage process","variant":"success"}],"kpis":[{"label":"Processing time","value":"12–24m","sub":"Stage 1 provisional","tone":"primary"},{"label":"Government fee","value":"AUD ,850+","sub":"Primary applicant approx","tone":"warning"},{"label":"Our approval rate","value":"89%","sub":"~79% benchmark","tone":"success"},{"label":"Required docs","value":"20","sub":"+ relationship evidence","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & medical","tone":"primary"}],"about":[{"label":"Description","value":"Partner visa for spouse or de facto partner of Australian citizen, permanent resident, or eligible NZ citizen. Provisional visa (309/820) then permanent (100/801) after relationship assessment period."},{"label":"Eligible applicants","value":"Married or de facto 12+ months · Genuine relationship · Health and character · Sponsor eligibility · Mutual commitment"},{"label":"Onshore vs offshore","value":"820/801 if partner in Australia on eligible visa. 309/100 if outside Australia. Bridging visa rules apply onshore.","warning":true},{"label":"Key authority","value":"Department of Home Affairs (Australia)"},{"label":"After approval","value":"Stage 1 provisional visa; Stage 2 permanent after waiting period and continued relationship evidence."}],"eligibility":[{"criterion":"Qualifying relationship (marriage or 12+ months de facto)","met":true},{"criterion":"Sponsor is eligible Australian citizen/PR/eligible NZ citizen","met":true},{"criterion":"Genuine and continuing relationship evidence","met":true},{"criterion":"Health requirements met","met":false},{"criterion":"Character requirements (police certs)","met":false},{"criterion":"Sponsorship obligations understood","met":true},{"criterion":"Correct onshore/offshore pathway","met":true,"note":"Assess partner location and visa status"}],"redFlagsBanner":"If refused on relationship grounds, rebuild chronological evidence before reapplication—do not resubmit same weak package.","redFlags":[{"title":"Weak relationship evidence","description":"Few photos, no cohabitation proof, inconsistent timeline.","fix":"Chronological narrative; communication logs; joint finances; visit evidence","severity":"Very common"},{"title":"Wrong pathway (onshore/offshore)","description":"Applied onshore without eligible visa status.","fix":"Verify partner visa and location before lodgement","severity":"High"},{"title":"De facto without 12 months cohabitation","description":"Unmarried without sufficient cohabitation evidence.","fix":"Marriage registration or 12+ months shared residence proof","severity":"High"},{"title":"Health/character issues","description":"Medical conditions or undisclosed criminal history.","fix":"Complete health exam early; disclose all history","severity":"Common"},{"title":"Prior refusals not addressed","description":"Hidden visa refusals or cancellations.","fix":"Full disclosure with changed circumstances","severity":"High"},{"title":"Sponsor ineligible","description":"Sponsor has prior sponsorship debt or ineligible status.","fix":"Verify sponsor eligibility on Home Affairs website","severity":"Medium"}],"faqs":[{"q":"Can we guarantee partner visa approval?","a":"No. Genuine relationships can still face refusals if evidence is insufficient."},{"q":"309/100 vs 820/801?","a":"309/100 offshore; 820/801 onshore when partner holds eligible visa in Australia."},{"q":"Can partner work on provisional visa?","a":"Generally full work rights on stage 1—verify grant conditions."},{"q":"How long until permanent visa?","a":"Typically 2 years on provisional before stage 2 assessment—verify current processing."},{"q":"Is marriage in India valid?","a":"Yes if legally registered; provide certified translation if needed."},{"q":"What if relationship is recent?","a":"Recent relationships need stronger evidence of development before marriage/de facto."},{"q":"Does prior student refusal matter?","a":"Must disclose all immigration history."},{"q":"Sponsorship obligations?","a":"Sponsor provides assurance of support; explain obligations to client."},{"q":"What is Description for this service?","a":"Partner visa for spouse or de facto partner of Australian citizen, permanent resident, or eligible NZ citizen. Provisional visa (309/820) then permanent (100/801) after relationship assessment period."},{"q":"What is Eligible applicants for this service?","a":"Married or de facto 12+ months · Genuine relationship · Health and character · Sponsor eligibility · Mutual commitment"},{"q":"What is Onshore vs offshore for this service?","a":"820/801 if partner in Australia on eligible visa. 309/100 if outside Australia. Bridging visa rules apply onshore."},{"q":"Important note on Onshore vs offshore?","a":"820/801 if partner in Australia on eligible visa. 309/100 if outside Australia. Bridging visa rules apply onshore."},{"q":"What is Key authority for this service?","a":"Department of Home Affairs (Australia)"},{"q":"What is After approval for this service?","a":"Stage 1 provisional visa; Stage 2 permanent after waiting period and continued relationship evidence."},{"q":"Is Qualifying relationship (marriage or 12+ months de facto) required?","a":"Qualifying relationship (marriage or 12+ months de facto) is typically required."},{"q":"Is Sponsor is eligible Australian citizen/PR/eligible NZ citizen required?","a":"Sponsor is eligible Australian citizen/PR/eligible NZ citizen is typically required."},{"q":"Is Genuine and continuing relationship evidence required?","a":"Genuine and continuing relationship evidence is typically required."},{"q":"Is Health requirements met required?","a":"Assess whether Health requirements met is satisfied for this case."},{"q":"Is Character requirements (police certs) required?","a":"Assess whether Character requirements (police certs) is satisfied for this case."},{"q":"Is Sponsorship obligations understood required?","a":"Sponsorship obligations understood is typically required."},{"q":"Is Correct onshore/offshore pathway required?","a":"Assess partner location and visa status"},{"q":"What is the Processing time?","a":"12–24m — Stage 1 provisional"},{"q":"What is the Government fee?","a":"AUD ,850+ — Primary applicant approx"},{"q":"What is the Our approval rate?","a":"89% — ~79% benchmark"},{"q":"What is the Required docs?","a":"20 — + relationship evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & medical"},{"q":"What if the client has Weak relationship evidence?","a":"Chronological narrative; communication logs; joint finances; visit evidence"},{"q":"Why is Weak relationship evidence a problem?","a":"Few photos, no cohabitation proof, inconsistent timeline."},{"q":"What if the client has Wrong pathway (onshore/offshore)?","a":"Verify partner visa and location before lodgement"},{"q":"Why is Wrong pathway (onshore/offshore) a problem?","a":"Applied onshore without eligible visa status."