UPDATE public.service_library
SET academy_metadata = '{"displayName":"Australia – Skilled Migration (Subclass 189/190/491)","shortDescription":"Home Affairs · Points-tested PR · Skills assessment · EOI","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":30,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current skills assessment fees and visa charges on homeaffairs.gov.au. Invitation depends on points and occupation ceiling—never promise invitation."},"alert":{"title":"Points and invitation required","body":"EOI in SkillSelect does not guarantee invitation. Points, occupation demand, and state nomination (190/491) determine outcome."},"tags":[{"label":"Active service","variant":"success"},{"label":"Points-tested","variant":"warning"},{"label":"6–18 months","variant":"neutral"},{"label":"Skills assessment","variant":"neutral"}],"chips":[{"label":"65+ points minimum","variant":"warning"},{"label":"Skills assessment","variant":"success"},{"label":"EOI then invitation","variant":"warning"},{"label":"No invite guarantee","variant":"warning"}],"kpis":[{"label":"Processing time","value":"6–18m","sub":"After invitation","tone":"primary"},{"label":"Government fee","value":"AUD $4,640+","sub":"Primary applicant approx","tone":"warning"},{"label":"Our approval rate","value":"88%","sub":"~80% post-invite benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ skills assessment","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & assessing body","tone":"primary"}],"about":[{"label":"Description","value":"Permanent residence via points-tested skilled migration. Subclass 189 (independent), 190 (state nominated), 491 (regional provisional). Requires skills assessment, EOI, and invitation."},{"label":"Eligible applicants","value":"Occupation on relevant skilled list · Positive skills assessment · 65+ points (competitive higher) · Age under 45 · Competent English · Health and character"},{"label":"Invitation not guaranteed","value":"Minimum 65 points does not guarantee invitation. Competitive scores often 80–90+ for popular occupations.","warning":true},{"label":"Key authority","value":"Department of Home Affairs · Skills assessing authorities · State/territory governments (190/491)"},{"label":"After approval","value":"Permanent visa (189/190) or provisional 491 leading to 191 PR. Meet residence conditions for regional visas."}],"eligibility":[{"criterion":"Occupation on skilled occupation list","met":true},{"criterion":"Positive skills assessment","met":false,"note":"Assessing authority specific"},{"criterion":"65+ points (competitive score)","met":true,"note":"Check recent invitation rounds"},{"criterion":"Age under 45 at invitation","met":true},{"criterion":"Competent English (IELTS 6 each band min)","met":true},{"criterion":"EOI submitted in SkillSelect","met":false},{"criterion":"Invitation received","met":false}],"redFlagsBanner":"Without invitation, do not lodge visa application. Improve points via PTE/IELTS, NAATI, partner skills, or state nomination before expecting invite.","redFlags":[{"title":"Points below competitive threshold","description":"Client has 65 points but occupation invites at 85+.","fix":"Improve English to superior; partner skills; state nomination 190/491","severity":"Very common"},{"title":"Skills assessment delayed or negative","description":"Assessing body finds insufficient experience or wrong ANZSCO.","fix":"Match ANZSCO duties; detailed reference letters before assessment","severity":"Very common"},{"title":"Age turning 45","description":"Will age out before invitation.","fix":"Expedite EOI; assess age points decline at 33 and 40","severity":"High"},{"title":"Wrong ANZSCO code","description":"Occupation code does not match actual duties.","fix":"Verify with assessing authority before skills assessment fee","severity":"Common"},{"title":"State nomination requirements not met","des