UPDATE public.service_library
SET academy_metadata = '{"displayName":"Australia – Work & Holiday Visa (1 year Work & Travel)","shortDescription":"Home Affairs · Subclass 417/462 · 12-month work & travel · Eligible passport required","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 7 Jun 2026","learningLevel":"Intermediate","learningMinutes":18,"policyAlert":{"active":true,"date":"7 Jun 2026","summary":"Confirm eligible passport list, age cap, and current WHM visa fee on homeaffairs.gov.au before quoting. India is not on the standard WHM list — verify country eligibility first."},"alert":{"title":"Passport country eligibility","body":"Working Holiday visas are only for specific passport countries. Confirm subclass 417 vs 462 and that the client has not held a WHM visa before."},"tags":[{"label":"Active service","variant":"success"},{"label":"Passport check","variant":"warning"},{"label":"2–8 weeks","variant":"neutral"},{"label":"Online – ImmiAccount","variant":"neutral"}],"chips":[{"label":"12-month stay","variant":"success"},{"label":"AUD ~$635 fee","variant":"neutral"},{"label":"Eligible passport","variant":"warning"},{"label":"Holiday + work","variant":"success"}],"kpis":[{"label":"Processing time","value":"2–8w","sub":"Country-dependent","tone":"primary"},{"label":"Government fee","value":"AUD ~$635","sub":"Verify on homeaffairs.gov.au","tone":"warning"},{"label":"Our approval rate","value":"88%","sub":"~76% industry benchmark","tone":"success"},{"label":"Required docs","value":"12","sub":"+ health / police if requested","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & insurance","tone":"primary"}],"about":[{"label":"Description","value":"Temporary visa for young adults from eligible countries to holiday in Australia and work short-term to fund their trip. Subclass 417 (Working Holiday) or 462 (Work and Holiday) depending on passport country."},{"label":"Eligible applicants","value":"Eligible passport · Age 18–30 (35 for some countries) · First WHM visa · Sufficient funds · Health & character · No dependent children accompanying"},{"label":"Work conditions","value":"Generally work for any employer up to 6 months; specified work in regional areas may support second WHM — verify current rules.","warning":true},{"label":"Key authority","value":"Department of Home Affairs (Australia)"},{"label":"After approval","value":"12-month stay from first entry; maintain insurance and visa conditions; TFN for lawful work."}],"eligibility":[{"criterion":"Passport from eligible WHM country","met":true,"note":"Verify Home Affairs list"},{"criterion":"Age within limit at application","met":true},{"criterion":"First Working Holiday Maker visa","met":true},{"criterion":"Sufficient funds (~AUD 5,000+)","met":true},{"criterion":"Adequate health insurance for stay","met":true},{"criterion":"Health & character requirements","met":false,"note":"If requested"},{"criterion":"Not bringing dependent children","met":true},{"criterion":"Genuine intention to holiday/work temporarily","met":true}],"redFlagsBanner":"If passport country is not eligible or client held WHM before, do not lodge — explore other visa options.","redFlags":[{"title":"Ineligible passport country","description":"Passport not on 417/462 list.","fix":"Verify list; do not lodge WHM","severity":"Very common"},{"title":"Age over limit at lodgement","description":"Applicant too old for WHM.","fix":"Confirm age on application date","severity":"Very common"},{"title":"Prior WHM visa held","description":"Already used first WHM.","fix":"Check visa history; second WHM only if eligible","severity":"High"},{"title":"Insufficient funds","description":"Cannot show ~AUD 5,000 or equivalent.","fix":"Bank statements, sponsor letter if allowed","severity":"Common"},{"title":"No health insurance","description":"Inadequate cover for stay.","fix":"OVHC or acceptable policy for full stay","severity":"Common"},{"title":"Employment-focused motive","description":"File looks like work migration not holiday.","fix":"Holiday plan, return ties, realistic itinerary","severity":"Medium"}],"faqs":[{"q":"Can Indian passport holders get WHM?","a":"India is not on the standard Working Holiday eligible passport list. Always verify the current Home Affairs list for the client passport country before quoting."},{"q":"417 vs 462 difference?","a":"Subclass 417 is Working Holiday for most eligible countries; 462 Work and Holiday applies to specific passport countries with separate caps and rules."},{"q":"How long can they stay?","a":"Generally 12 months from first entry. Extensions or second WHM only in limited circumstances — verify current policy."},{"q":"How much funds needed?","a":"Typically around AUD 5,000 plus return travel costs. Must be credible and available to the applicant."},{"q":"Can they work full-time?","a":"WHM allows work to supplement holiday but primary purpose is holiday. Condition 8547 limits work with same employer to 6 months unless exempt."},{"q":"Can they study?","a":"Generally up to 4 months study permitted — verify current conditions."},{"q":"Can partner come?","a":"Dependants cannot be included on WHM application."},{"q":"Second WHM possible?","a":"May be available if specified regional work completed on first WHM — verify current requirements."},{"q":"Processing time?","a":"Often 2–8 weeks but varies by office and season — check global processing times."},{"q":"Government fee?","a":"Verify current fee on visa pricing estimator — approximately AUD 635 but subject to change."},{"q":"Health insurance required?","a":"Yes — adequate health insurance for entire stay is required."},{"q":"Police check required?","a":"Only if requested by Home Affairs based on profile and countries lived."},{"q":"Biometrics required?","a":"Often yes for offshore applicants — follow ImmiAccount instructions."},{"q":"Can apply from inside Australia?","a":"Generally WHM is applied offshore — verify if client holds bridging visa."},{"q":"What if refused?","a":"Review refusal letter; may reapply only if circumstances change materially."},{"q":"What is Description for this service?","a":"Temporary visa for young adults from eligible countries to holiday in Australia and work short-term to fund their trip. Subclass 417 (Working Holiday) or 462 (Work and Holiday) depending on passport country."},{"q":"What is Eligible applicants for this service?","a":"Eligible passport · Age 18–30 (35 for some countries) · First WHM visa · Sufficient funds · Health & character · No dependent children accompanying"},{"q":"What is Work conditions for this service?","a":"Generally work for any employer up to 6 months; specified work in regional areas may support second WHM — verify current rules."},{"q":"What is Key authority for this service?","a":"Department of Home Affairs (Australia)"},{"q":"What is After approval for this service?","a":"12-month stay from first entry; maintain insurance and visa conditions; TFN for lawful work."},{"q":"What is the Processing time?","a":"2–8w — Country-dependent"},{"q":"What is the Government fee?","a":"AUD ~$635 — Verify on homeaffairs.gov.au"},{"q":"What is the Our approval rate?","a":"88% — ~76% industry benchmark"},{"q":"What is the Required docs?","a":"12 — + health / police if requested"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if Ineligible passport country?","a":"Verify list; do not lodge WHM"},{"q":"What if Age over limit at lodgement?","a":"Confirm age on application date"},{"q":"What if Prior WHM visa held?","a":"Check visa history; second WHM only if eligible"},{"q":"Where to verify WHM eligibility and fees?","a":"immi.homeaffairs.gov.au — eligible passport list, subclass 417/462 pages, and visa pricing estimator."},{"q":"Where to verify WHM eligibility and fees?","a":"immi.homeaffairs.gov.au — eligible passport list, subclass 417/462 pages, and visa pricing estimator."}],"compliance":["Client service agreement on file before eligibility screen","Never guarantee WHM approval","Separate consultancy and government visa fees","Screen passport country eligibility before fee collection","Brief client on 6-month employer rule and insurance conditions"],"proTips":["Screen passport country before marketing WHM to client","Confirm age on application date not intake date","Use realistic holiday narrative — not full-time job offer focus","Arrange OVHC before lodgement","Brief client on 6-month employer rule after grant"],"postApproval":["Send grant letter and entry instructions","Explain work and study conditions","Guide TFN, bank account, and super basics","Remind insurance must stay active"],"performance":{"ourRate":88,"industryRate":76,"stats":[{"label":"Files this year","value":"42"},{"label":"Approved","value":"37"},{"label":"Refused","value":"4"},{"label":"Ineligible screened out","value":"18"}]},"approvalFactors":[{"label":"Passport eligibility","ours":100,"benchmark":95},{"label":"Funds evidence","ours":90,"benchmark":78},{"label":"First-submit completeness","ours":92,"benchmark":82}],"timeline":[{"weeks":"1","title":"Eligibility screen — passport, age, WHM history"},{"weeks":"1–2","title":"Documents, funds, insurance, ImmiAccount"},{"weeks":"2–3","title":"Lodgement & biometrics"},{"weeks":"2–8","title":"Home Affairs processing"}],"relatedServices":[{"label":"Australia – Student Visa (Subclass 500)","libraryId":"b2000001-0001-4000-8000-000000000041"},{"label":"Australia – Visitor Visa (Subclass 600)","libraryId":"b2000001-0001-4000-8000-000000000042"},{"label":"Australia – Skilled Migration","libraryId":"b2000001-0001-4000-8000-000000000044"}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level); aligned with Visitor Visa template."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"7 Jun 2026","author":"Service Library","summary":"Initial Work & Holiday counselor content and branded checklist."}],"staffNotes":[{"author":"Documentation team","date":"7 Jun 2026","text":"Always verify passport eligibility before fee collection. WHM is not available to all nationalities."}],"resources":[{"title":"Home Affairs — Working Holiday visa (417)","url":"https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/work-holiday-417","description":"Official 417 requirements"},{"title":"Home Affairs — Work and Holiday visa (462)","url":"https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/work-and-holiday-462","description":"Official 462 requirements"},{"title":"Eligible countries list","url":"https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/work-holiday-417/eligibility","description":"Passport eligibility"},{"title":"Home Affairs — Visa pricing","url":"https://immi.homeaffairs.gov.au/visas/visa-pricing-estimator","description":"Current fees"},{"title":"Home Affairs — Processing times","url":"https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-processing-times/global-visa-processing-times","description":"Estimates"}],"quiz":[{"question":"Primary purpose of WHM visa?","options":["Permanent migration","Holiday with incidental work","Full-time employment only","Long-term study"],"correctIndex":1,"explanation":"WHM is a temporary holiday visa with limited work rights.","level":1},{"question":"Typical maximum initial stay on first WHM?","options":["3 months","6 months","12 months","4 years"],"correctIndex":2,"explanation":"First WHM is generally 12 months from first entry.","level":1},{"question":"Can dependent children be included on WHM?","options":["Yes with sponsor","Yes with extra fee","No — not permitted","Only under age 12"],"correctIndex":2,"explanation":"WHM cannot include dependants.","level":1},{"question":"WHM is available to which passport holders?","options":["All nationalities","Only Australian citizens","Eligible passport coun