{"label":"Blocked account","value":"€11,904 for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies.","warning":true},{"label":"Key authority","value":"German Embassy/Consulate in India · Federal Foreign Office · Local Ausländerbehörde after arrival"},{"label":"After approval","value":"Enter Germany; register address; apply for residence permit at Ausländerbehörde within visa validity."}],"eligibility":[{"criterion":"Admission from recognised German institution","met":true},{"criterion":"APS certificate (India)","met":false,"note":"Apply early—processing takes weeks"},{"criterion":"Blocked account or financial proof","met":false,"note":"€11,904 for 2026 or equivalent"},{"criterion":"Health insurance (travel + statutory)","met":false},{"criterion":"Motivation letter and CV","met":true},{"criterion":"Language proficiency (as required)","met":true,"note":"German or English per program"},{"criterion":"Valid passport","met":true}],"redFlagsBanner":"After refusal, address embassy feedback before rebooking—blocked account and APS cannot be rushed last minute.","redFlags":[{"title":"APS not completed","description":"Visa appointment booked without APS certificate.","fix":"Complete APS before embassy slot; track processing on APS website","severity":"Very common"},{"title":"Insufficient blocked account","description":"Amount below required monthly sum or not from recognised provider.","fix":"Open blocked account at approved bank for full required amount","severity":"Very common"},{"title":"Admission not from recognised institution","description":"Private unrecognised college or expired Zulassung.","fix":"Verify Anabin/institution recognition before fees","severity":"Common"},{"title":"Weak motivation letter","description":"Generic letter not explaining study plan and Germany choice.","fix":"Course-specific motivation linking prior study to German program","severity":"Common"},{"title":"Language proof missing","description":"Program requires German/English certificate not provided.","fix":"Obtain required TestDaF/IELTS/Goethe per admission","severity":"Common"},{"title":"Prior refusals not addressed","description":"Schengen or German refusals hidden.","fix":"Disclose and explain changed circumstances","severity":"High"}],"faqs":[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is APS?","a":"Academic Evaluation Centre verification for Indian academic documents—mandatory for most Indian student visa applicants."},{"q":"Blocked account amount for 2026?","a":"Typically €11,904 (12 months × €992). Verify current amount before opening account."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need German?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Ausländerbehörde soon after arrival and registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Germany."},{"q":"What after graduation?","a":"Discuss 18-month job-seeker residence permit or Opportunity Card separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised German university or preparatory course. After entry, convert to residence permit at local Ausländerbehörde."},{"q":"What is Eligible applicants for this service?","a":"University admission (Zulassung) or conditional admission · Blocked account or scholarship · APS certificate (India) · Health insurance · Motivation letter"},{"q":"What is Blocked account for this service?","a":"€11,904 for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Blocked account?","a":"€11,904 for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"German Embassy/Consulate in India · Federal Foreign Office · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Germany; register address; apply for residence permit at Ausländerbehörde within visa validity."},{"q":"Is Admission from recognised German institution required?","a":"Admission from recognised German institution is typically required."},{"q":"Is APS certificate (India) required?","a":"Apply early—processing takes weeks"},{"q":"Is Blocked account or financial proof required?","a":"€11,904 for 2026 or equivalent"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"German or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file + APS"},{"q":"What is the Government fee?","a":"€75 — + blocked account €11,904"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + APS & blocked account"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has APS not completed?","a":"Complete APS before embassy slot; track processing on APS website"},{"q":"Why is APS not completed a problem?","a":"Visa appointment booked without APS certificate."},{"q":"What if the client has Insufficient blocked account?","a":"Open blocked account at approved bank for full required amount"},{"q":"Why is Insufficient blocked account a problem?","a":"Amount below required monthly sum or not from recognised provider."}],"compliance":["Client service agreement and consent