SET academy_metadata = '{"displayName":"Germany – Spouse / Family Reunion Visa","shortDescription":"German Embassy · Family reunion · Spouse of German/resident · Language A1","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":25,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current national visa fee (€75 approx) and German language A1 requirement for spouses on auswaertiges-amt.de before quoting."},"alert":{"title":"Sponsor status in Germany","body":"Spouse must be German citizen or holder of valid residence permit with sufficient space and income. Verify sponsor status before fee collection."},"tags":[{"label":"Active service","variant":"success"},{"label":"A1 German often required","variant":"warning"},{"label":"8–16 weeks","variant":"neutral"},{"label":"Embassy appointment","variant":"neutral"}],"chips":[{"label":"8–16 weeks","variant":"neutral"},{"label":"€75 visa fee","variant":"neutral"},{"label":"Relationship proof","variant":"warning"},{"label":"Sponsor in Germany","variant":"success"}],"kpis":[{"label":"Processing time","value":"8–16w","sub":"After complete file","tone":"primary"},{"label":"Government fee","value":"€75","sub":"National visa approx","tone":"warning"},{"label":"Our approval rate","value":"87%","sub":"~76% benchmark","tone":"success"},{"label":"Required docs","value":"18","sub":"+ relationship & sponsor","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & language test","tone":"primary"}],"about":[{"label":"Description","value":"National visa for spouse reunion with German citizen or foreign national holding qualifying residence permit in Germany. Leads to residence permit after entry."},{"label":"Eligible applicants","value":"Valid marriage · Sponsor with adequate housing and income · Basic German A1 (generally) · Genuine relationship · Health insurance"},{"label":"Language requirement","value":"Spouses generally need German A1 certificate unless exempt (e.g., certain qualifications or EU nationals). Verify exemptions.","warning":true},{"label":"Key authority","value":"German Embassy in India · Ausländerbehörde in Germany after arrival"},{"label":"After approval","value":"Enter Germany; register address; obtain residence permit at local Ausländerbehörde."}],"eligibility":[{"criterion":"Legally valid marriage recognised in Germany","met":true},{"criterion":"Sponsor is German citizen or qualifying resident","met":true,"note":"Verify residence permit type"},{"criterion":"Adequate housing in Germany","met":true,"note":"Sponsor lease/ownership proof"},{"criterion":"Sponsor income/solvency","met":true,"note":"Per German requirements"},{"criterion":"German A1 certificate (if required)","met":false,"note":"Goethe/ÖSD/TELC A1"},{"criterion":"Genuine relationship evidence","met":true},{"criterion":"Health insurance arrangement","met":false}],"redFlagsBanner":"If refused, address embassy concerns on relationship or sponsor eligibility before reapplication.","redFlags":[{"title":"Sponsor income/housing insufficient","description":"Sponsor cannot prove adequate apartment size or income.","fix":"Collect sponsor employment contract, salary slips, lease with square metres","severity":"Very common"},{"title":"Missing A1 German certificate","description":"Spouse applied without required basic German.","fix":"Complete Goethe A1 or verify exemption applies","severity":"Common"},{"title":"Weak relationship evidence","description":"Few photos, no visit history, recent marriage unexplained.","fix":"Chronological relationship timeline; visit stamps; communication logs","severity":"Common"},{"title":"Marriage not registered/apostilled","description":"Indian marriage certificate not properly legalised.","fix":"Apostille and certified German translation","severity":"Common"},{"title":"Sponsor permit expiring","description":"Sponsor residence permit near expiry or uncertain status.","fix":"Verify sponsor valid long-term status before apply","severity":"High"},{"title":"Prior refusals hidden","description":"Schengen or national visa refusals not disclosed.","fix":"Full disclosure in cover letter","severity":"High"}],"faqs":[{"q":"Can we guarantee spouse visa approval?","a":"No. Embassy assesses marriage genuineness, sponsor status, and requirements. Never promise approval."},{"q":"Is A1 German mandatory for all spouses?","a":"Generally yes for spouses of non-EU residents; exemptions exist—verify on embassy website for specific case."},{"q":"How long sponsor must be in Germany?","a":"Depends on sponsor status—German citizens differ from permit holders. Verify current AufenthG requirements."},{"q":"Can unmarried partners apply?","a":"Family reunion typically requires marriage; registered partnership rules vary—assess separately."},{"q":"What documents from sponsor?","a":"Passport/ID, registration, lease, employment, salary, marriage cert from Standesamt if married in Germany."},{"q":"Processing time?","a":"Typically 8–16 weeks after complete submission—varies by embassy workload."},{"q":"Can spouse work after arrival?","a":"Work authorisation depends on residence permit granted—verify at Ausländerbehörde."},{"q":"Prior Schengen refusal impact?","a":"Must disclose; may affect assessment."},{"q":"What is Description for this service?","a":"National visa for spouse reunion with German citizen or foreign national holding qualifying residence permit in Germany. Leads to residence permit after entry."},{"q":"What is Eligible applicants for this service?","a":"Valid marriage · Sponsor with adequate housing and income · Basic German A1 (generally) · Genuine relationship · Health insurance"},{"q":"What is Language requirement for this service?","a":"Spouses generally need German A1 certificate unless exempt (e.g., certain qualifications or EU nationals). Verify exemptions."},{"q":"Important note on Language requirement?","a":"Spouses generally need German A1 certificate unless exempt (e.g., certain qualifications or EU nationals). Verify exemptions."},{"q":"What is Key authority for this service?","a":"German Embassy in India · Ausländerbehörde in Germany after arrival"},{"q":"What is After approval for this service?","a":"Enter Germany; register address; obtain residence permit at local Ausländerbehörde."},{"q":"Is Legally valid marriage recognised in Germany required?","a":"Legally valid marriage recognised in Germany is typically required."},{"q":"Is Sponsor is German citizen or qualifying resident required?","a":"Verify residence permit type"},{"q":"Is Adequate housing in Germany required?","a":"Sponsor lease/ownership proof"},{"q":"Is Sponsor income/solvency required?","a":"Per German requirements"},{"q":"Is German A1 certificate (if required) required?","a":"Goethe/ÖSD/TELC A1"},{"q":"Is Genuine relationship evidence required?","a":"Genuine relationship evidence is typically required."},{"q":"Is Health insurance arrangement required?","a":"Assess whether Health insurance arrangement is satisfied for this case."},{"q":"What is the Processing time?","a":"8–16w — After complete file"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"87% — ~76% benchmark"},{"q":"What is the Required docs?","a":"18 — + relationship & sponsor"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & language test"},{"q":"What if the client has Sponsor income/housing insufficient?","a":"Collect sponsor employment contract, salary slips, lease with square metres"},{"q":"Why is Sponsor income/housing insufficient a problem?","a":"Sponsor cannot prove adequate apartment size or income."},{"q":"What if the client has Missing A1 German certificate?","a":"Complete Goethe A1 or verify exemption applies"},{"q":"Why is Missing A1 German certificate a problem?","a":"Spouse applied without required basic German."}],"compliance":["Client service agreement on file before submission","Never guarantee visa approval","Marriage documents must be genuine and properly legalised","Separate consultancy and embassy fees"],"proTips":["Verify sponsor status and housing before India-side fee collection","Start A1 German early—exam slots fill fast","Apostille marriage certificate with certified translation","Build relationship timeline with visit evidence","Coordinate with sponsor for original German-side documents"],"postApproval":["Explain Anmeldung registration deadline","Guide on Ausländerbehörde residence permit appointment","Advise on integration courses if required","Connect to German language resources"],"performance":{"ourRate":87,"industryRate":76,"stats":[{"label":"Files this year","value":"29"},{"label":"Approved","value":"25"},{"label":"Refused","value":"3"},{"label":"Withdrawn","value":"1"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":87,"benchmark":76},{"label":"Sponsor documentation","ours":85,"benchmark":70},{"label":"Relationship evidence","ours":84,"benchmark":72},{"label":"First-submit completeness","ours":91,"benchmark":74}],"timeline":[{"weeks":"1–2","title":"Sponsor eligibility check, A1 planning"},{"weeks":"2–8","title":"A1 exam, document collection, legalisation"},{"weeks":"8–10","title":"Embassy appointment & submission"},{"weeks":"8–16","title":"Embassy processing"}],"relatedServices":[{"label":"Germany – Student Visa","libraryId":""},{"label":"Germany – Job Seeker Visa","libraryId":""},{"label":"Germany – Opportunity Card","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded quiz to 75 levelled questions (25 per level)."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial Germany spouse reunion visa counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Coordinate