rvice?","a":"German Embassy in India · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Germany; search for qualified employment; convert to work residence permit when job secured."},{"q":"Is Minimum 6 points achieved required?","a":"Calculate using official criteria"},{"q":"Is Recognised degree or IT experience pathway required?","a":"Recognised degree or IT experience pathway is typically required."},{"q":"Is German A1 or English B2 required?","a":"German A1 or English B2 is typically required."},{"q":"Is Blocked account or job offer required?","a":"Financial proof required"},{"q":"Is Qualification recognition (if claiming points) required?","a":"Anabin or partial recognition"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Health insurance required?","a":"Assess whether Health insurance is satisfied for this case."},{"q":"What is the Processing time?","a":"8–12w — Embassy processing"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"82% — ~70% benchmark"},{"q":"What is the Required docs?","a":"14 — + points evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & blocked account"},{"q":"What if the client has Below 6 points?","a":"Calculate points honestly; improve language or get recognition"},{"q":"Why is Below 6 points a problem?","a":"Application lodged without meeting minimum points."},{"q":"What if the client has Qualification not recognised?","a":"Check Anabin database; apply for recognition if needed"},{"q":"Why is Qualification not recognised a problem?","a":"Degree not equivalent to German qualification for points."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee visa or immigration approval; use approved-language only","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Calculate 6 points at 