UPDATE public.service_library
SET academy_metadata = '{"displayName":"New Zealand – Skilled Migrant Category (SMC)","shortDescription":"Immigration NZ · Points-based PR · EOI · Job offer or skilled employment","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Advanced","learningMinutes":28,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current SMC points requirements and fees on immigration.govt.nz. Expression of Interest selection depends on points threshold—never promise selection."},"alert":{"title":"EOI selection not guaranteed","body":"Submitting Expression of Interest does not guarantee selection. Points threshold varies each ballot—counsel on realistic points before fees."},"tags":[{"label":"Active service","variant":"success"},{"label":"Points-tested","variant":"warning"},{"label":"6–18 months","variant":"neutral"},{"label":"EOI system","variant":"neutral"}],"chips":[{"label":"Points-based","variant":"warning"},{"label":"NZD $4,890 approx","variant":"neutral"},{"label":"Skilled job required","variant":"success"},{"label":"No selection guarantee","variant":"warning"}],"kpis":[{"label":"Processing time","value":"6–18m","sub":"After ITA","tone":"primary"},{"label":"Government fee","value":"NZD $4,890","sub":"Residence approx—verify","tone":"warning"},{"label":"Our approval rate","value":"86%","sub":"~78% post-ITA benchmark","tone":"success"},{"label":"Required docs","value":"17","sub":"+ qualifications & experience","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt & assessments","tone":"primary"}],"about":[{"label":"Description","value":"Permanent residence pathway for skilled workers with qualifications and experience needed in New Zealand. Points-based Expression of Interest (EOI) system with periodic selection."},{"label":"Eligible applicants","value":"Skilled employment or job offer · Points meeting selection threshold · Age typically under 55 · English competency · Health and character · Qualifications assessment if required"},{"label":"Selection threshold varies","value":"INZ selects EOIs above certain points at each ballot. Threshold changes—verify recent selections.","warning":true},{"label":"Key authority","value":"Immigration New Zealand (INZ)"},{"label":"After approval","value":"Permanent residence visa; live and work in New Zealand indefinitely subject to travel conditions on initial visa."}],"eligibility":[{"criterion":"Skilled job offer or current skilled employment in NZ","met":true},{"criterion":"Points meet or exceed recent selection threshold","met":false,"note":"Check recent ballots"},{"criterion":"Age under 55 (for maximum points)","met":true},{"criterion":"English competency (IELTS 6.5 avg or equivalent)","met":true},{"criterion":"Qualification assessment (if required)","met":false},{"criterion":"EOI submitted and selected","met":false},{"criterion":"Health and character clearances","met":false}],"redFlagsBanner":"Without EOI selection, do not lodge residence application. Improve points via NZ employment, qualification level, or work experience before expecting selection.","redFlags":[{"title":"Points below selection threshold","description":"EOI submitted but recent selections at higher points.","fix":"Gain NZ skilled work experience; improve English; partner qualifications","severity":"Very common"},{"title":"Job not skilled (ANZSCO)","description":"Occupation below skill level 1–3 or not on green list.","fix":"Verify ANZSCO skill level and green list eligibility","severity":"Very common"},{"title":"Qualification not recognised","description":"Overseas qualification not assessed or equivalent.","fix":"Complete NZQA International Qualification Assessment","severity":"Common"},{"title":"Age over 55","description":"Zero age points; difficult to reach threshold.","fix":"Assess alternative visa pathways","severity":"High"},{"title":"English below requirement","description":"IELTS scores below 6.5 average.","fix":"Retake for higher scores","severity":"Common"},{"title":"EOI selected but docs not ready","description":"Missed invitation to apply deadline.","fix":"Prepare document templates while EOI in pool","severity":"High"}],"faqs":[{"q":"Can we guarantee SMC selection or PR?","a":"No. EOI selection depends on points and INZ ballot. Never promise selection or approval."},{"q":"How many points needed?","a":"Check recent INZ selection announcements—threshold varies each ballot."},{"q":"Need job offer?","a":"Skilled employment in NZ or job offer typically required—verify current SMC rules."},{"q":"Green List fast track?","a":"Some occupations on Green List have simplified residence pathways—assess separately."},{"q":"Partner points?","a":"Partner qualifications and skilled employment may add points."},{"q":"Processing after ITA?","a":"Typically several months—verify current INZ processing times."},{"q":"Can apply from India?","a":"Generally need NZ job offer or be in NZ on eligible visa—verify current rules."},{"q":"NZQA assessment required?","a":"For many overseas qualifications—verify if needed for points claim."},{"q":"What is Description for this service?","a":"Permanent residence pathway for skilled workers with qualifications and experience needed in New Zealand. Points-based Expression of Interest (EOI) system with periodic selection."},{"q":"What is Eligible applicants for this service?","a":"Skilled employment or job offer · Points meeting selection threshold · Age typically under 55 · English competency · Health and character · Qualifications assessment if required"},{"q":"What is Selection threshold varies for this service?","a":"INZ selects EOIs above certain points at each ballot. Threshold changes—verify recent selections."},{"q":"Important note on Selection threshold varies?","a":"INZ selects EOIs above certain points at each ballot. Threshold changes—verify recent selections."},{"q":"What is Key authority for this service?","a":"Immigration New Zealand (INZ)"},{"q"